import { vi } from 'vitest';
import type {
  AIProvider,
  ChatCompletionRequest,
  ChatCompletionResponse,
  EmbeddingRequest,
  EmbeddingResponse,
} from '@/lib/ai/types';

/** Default canned chat completion response */
const defaultChatResponse: ChatCompletionResponse = {
  content: 'This is a mock response.',
  toolCalls: [],
  finishReason: 'stop',
  usage: {
    promptTokens: 10,
    completionTokens: 8,
    totalTokens: 18,
  },
  model: 'mock-model',
};

/** Default canned embedding response (1536-dim zero vector) */
const defaultEmbeddingResponse: EmbeddingResponse = {
  embeddings: [new Array(1536).fill(0) as number[]],
  model: 'mock-embedding-model',
  usage: {
    promptTokens: 5,
    totalTokens: 5,
  },
};

/**
 * Mock AIProvider implementing the AIProvider interface.
 * All methods are vi.fn() stubs with sensible default return values.
 */
export const mockAIProvider: AIProvider = {
  name: 'mock',

  chatCompletion: vi.fn<[ChatCompletionRequest], Promise<ChatCompletionResponse>>(
    async (_request) => ({ ...defaultChatResponse }),
  ),

  generateEmbeddings: vi.fn<[EmbeddingRequest], Promise<EmbeddingResponse>>(
    async (_request) => ({ ...defaultEmbeddingResponse }),
  ),

  healthCheck: vi.fn<[], Promise<boolean>>(async () => true),
};

/** Reset all mock function call history between tests */
export function resetAIProviderMocks(): void {
  (mockAIProvider.chatCompletion as ReturnType<typeof vi.fn>).mockReset();
  (mockAIProvider.generateEmbeddings as ReturnType<typeof vi.fn>).mockReset();
  (mockAIProvider.healthCheck as ReturnType<typeof vi.fn>).mockReset();

  // Restore default implementations after reset
  (mockAIProvider.chatCompletion as ReturnType<typeof vi.fn>).mockImplementation(
    async () => ({ ...defaultChatResponse }),
  );
  (mockAIProvider.generateEmbeddings as ReturnType<typeof vi.fn>).mockImplementation(
    async () => ({ ...defaultEmbeddingResponse }),
  );
  (mockAIProvider.healthCheck as ReturnType<typeof vi.fn>).mockImplementation(async () => true);
}

