     1→/**
     2→ * Structured error types for Sandra.
     3→ * Provides consistent error handling across the platform.
     4→ */
     5→
     6→export type ErrorCode =
     7→  | 'VALIDATION_ERROR'
     8→  | 'NOT_FOUND'
     9→  | 'UNAUTHORIZED'
    10→  | 'FORBIDDEN'
    11→  | 'RATE_LIMITED'
    12→  | 'PROVIDER_ERROR'
    13→  | 'INTERNAL_ERROR'
    14→  | 'CONFIGURATION_ERROR'
    15→  | 'TOOL_EXECUTION_ERROR'
    16→  | 'CHANNEL_ERROR'
    17→  | 'INDEXING_ERROR';
    18→
    19→export class SandraError extends Error {
    20→  public readonly code: ErrorCode;
    21→  public readonly statusCode: number;
    22→  public readonly details?: Record<string, unknown>;
    23→
    24→  constructor(
    25→    message: string,
    26→    code: ErrorCode = 'INTERNAL_ERROR',
    27→    statusCode = 500,
    28→    details?: Record<string, unknown>,
    29→  ) {
    30→    super(message);
    31→    this.name = 'SandraError';
    32→    this.code = code;
    33→    this.statusCode = statusCode;
    34→    this.details = details;
    35→  }
    36→
    37→  toJSON() {
    38→    return {
    39→      error: {
    40→        code: this.code,
    41→        message: this.message,
    42→        ...(this.details ? { details: this.details } : {}),
    43→      },
    44→    };
    45→  }
    46→}
    47→
    48→export class ValidationError extends SandraError {
    49→  constructor(message: string, details?: Record<string, unknown>) {
    50→    super(message, 'VALIDATION_ERROR', 400, details);
    51→    this.name = 'ValidationError';
    52→  }
    53→}
    54→
    55→export class NotFoundError extends SandraError {
    56→  constructor(resource: string, id?: string) {
    57→    super(
    58→      id ? `${resource} with id '${id}' not found` : `${resource} not found`,
    59→      'NOT_FOUND',
    60→      404,
    61→    );
    62→    this.name = 'NotFoundError';
    63→  }
    64→}
    65→
    66→export class ProviderError extends SandraError {
    67→  constructor(provider: string, message: string, details?: Record<string, unknown>) {
    68→    super(`[${provider}] ${message}`, 'PROVIDER_ERROR', 502, details);
    69→    this.name = 'ProviderError';
    70→  }
    71→}
    72→
    73→export class ConfigurationError extends SandraError {
    74→  constructor(message: string) {
    75→    super(message, 'CONFIGURATION_ERROR', 500);
    76→    this.name = 'ConfigurationError';
    77→  }
    78→}
    79→
    80→export class ToolExecutionError extends SandraError {
    81→  constructor(toolName: string, message: string, details?: Record<string, unknown>) {
    82→    super(`Tool '${toolName}' failed: ${message}`, 'TOOL_EXECUTION_ERROR', 500, details);
    83→    this.name = 'ToolExecutionError';
    84→  }
    85→}
    86→
    87→/**
    88→ * Wrap an async operation with structured error handling.
    89→ */
    90→export async function withErrorHandling<T>(
    91→  operation: () => Promise<T>,
    92→  context: string,
    93→): Promise<T> {
    94→  try {
    95→    return await operation();
    96→  } catch (error) {
    97→    if (error instanceof SandraError) throw error;
    98→    const message = error instanceof Error ? error.message : 'Unknown error';
    99→    throw new SandraError(`${context}: ${message}`, 'INTERNAL_ERROR', 500);
   100→  }
   101→}
   102→
   103→/**
   104→ * Create a structured API error response.
   105→ */
   106→export function errorResponse(error: unknown): { error: { code: ErrorCode; message: string }; status: number } {
   107→  if (error instanceof SandraError) {
   108→    return { error: { code: error.code, message: error.message }, status: error.statusCode };
   109→  }
   110→  const message = error instanceof Error ? error.message : 'An unexpected error occurred';
   111→  return { error: { code: 'INTERNAL_ERROR', message }, status: 500 };
   112→}
   113→

