     3→
     4→/**
     5→ * Validate data against a Zod schema, throwing a structured error on failure.
     6→ */
     7→export function validate<T>(schema: z.ZodSchema<T>, data: unknown, context?: string): T {
     8→  const result = schema.safeParse(data);
     9→  if (!result.success) {
    10→    const issues = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`);
    11→    throw new ValidationError(
    12→      context ? `${context}: validation failed` : 'Validation failed',
    13→      { issues },
    14→    );
    15→  }
    16→  return result.data;
    17→}
    18→
    19→/**
    20→ * Generate a short ID from uuid v4 (first 8 chars).
    21→ */
    22→export function shortId(): string {
    23→  return crypto.randomUUID().slice(0, 8);
    24→}
    25→
    26→/**
    27→ * Truncate a string to a max length with ellipsis.
    28→ */
    29→export function truncate(str: string, max: number): string {
    30→  if (str.length <= max) return str;
    31→  return str.slice(0, max - 3) + '...';
    32→}
    33→
    34→/**
    35→ * Sleep for a given number of milliseconds.
    36→ */
    37→export function sleep(ms: number): Promise<void> {
    38→  return new Promise((resolve) => setTimeout(resolve, ms));
    39→}
    40→
    41→/**
    42→ * Safely parse JSON, returning null on failure.
    43→ */
    44→export function safeJsonParse<T = unknown>(str: string): T | null {
    45→  try {
    46→    return JSON.parse(str) as T;
    47→  } catch {
    48→    return null;
    49→  }
    50→}
