     3→import { createLogger, ProviderError } from '@/lib/utils';
     4→import type {
     5→  AIProvider,
     6→  ChatCompletionRequest,
     7→  ChatCompletionResponse,
     8→  EmbeddingRequest,
     9→  EmbeddingResponse,
    10→  ToolCall,
    11→} from './types';
    12→
    13→const log = createLogger('ai:openai');
    14→
    15→/**
    16→ * OpenAI provider implementation.
    17→ * First-class implementation of the AIProvider interface.
    18→ */
    19→export class OpenAIProvider implements AIProvider {
    20→  readonly name = 'openai';
    21→  private client: OpenAI;
    22→
    23→  constructor(apiKey?: string) {
    24→    this.client = new OpenAI({
    25→      apiKey: apiKey ?? env.OPENAI_API_KEY,
    26→    });
    27→  }
    28→
    29→  async chatCompletion(request: ChatCompletionRequest): Promise<ChatCompletionResponse> {
    30→    const model = request.model ?? env.OPENAI_MODEL;
    31→
    32→    try {
    33→      const messages = request.messages.map((m) => {
    34→        if (m.role === 'tool') {
    35→          return {
    36→            role: 'tool' as const,
    37→            content: m.content,
    38→            tool_call_id: m.toolCallId ?? '',
    39→          };
    40→        }
    41→        return {
    42→          role: m.role as 'system' | 'user' | 'assistant',
    43→          content: m.content,
    44→        };
    45→      });
    46→
    47→      const tools = request.tools?.map((t) => ({
    48→        type: 'function' as const,
    49→        function: {
    50→          name: t.name,
    51→          description: t.description,
    52→          parameters: t.parameters,
    53→        },
    54→      }));
    55→
    56→      const toolChoice = request.toolChoice
    57→        ? request.toolChoice === 'auto' || request.toolChoice === 'none'
    58→          ? request.toolChoice
    59→          : { type: 'function' as const, function: { name: request.toolChoice.name } }
    60→        : undefined;
    61→
    62→      const response = await this.client.chat.completions.create({
    63→        model,
    64→        messages,
    65→        temperature: request.temperature ?? 0.7,
    66→        max_tokens: request.maxTokens,
    67→        tools: tools && tools.length > 0 ? tools : undefined,
    68→        tool_choice: toolChoice,
    69→        stop: request.stop,
    70→      });
    71→
    72→      const choice = response.choices[0];
    73→      if (!choice) {
    74→        throw new ProviderError('openai', 'No choices returned in completion response');
    75→      }
    76→
    77→      const toolCalls: ToolCall[] = (choice.message.tool_calls ?? []).map((tc) => ({
    78→        id: tc.id,
    79→        name: tc.function.name,
    80→        arguments: tc.function.arguments,
    81→      }));
    82→
    83→      const finishReason = choice.finish_reason === 'tool_calls' ? 'tool_calls' : choice.finish_reason ?? 'stop';
    84→
    85→      return {
    86→        content: choice.message.content,
    87→        toolCalls,
    88→        finishReason: finishReason as ChatCompletionResponse['finishReason'],
    89→        usage: {
    90→          promptTokens: response.usage?.prompt_tokens ?? 0,
    91→          completionTokens: response.usage?.completion_tokens ?? 0,
    92→          totalTokens: response.usage?.total_tokens ?? 0,
    93→        },
    94→        model: response.model,
    95→      };
    96→    } catch (error) {
    97→      if (error instanceof ProviderError) throw error;
    98→      const msg = error instanceof Error ? error.message : 'Unknown OpenAI error';
    99→      log.error('Chat completion failed', { error: msg, model });
   100→      throw new ProviderError('openai', msg);
   101→    }
   102→  }
   103→
   104→  async generateEmbeddings(request: EmbeddingRequest): Promise<EmbeddingResponse> {
   105→    const model = request.model ?? env.OPENAI_EMBEDDING_MODEL;
   106→
   107→    try {
   108→      const response = await this.client.embeddings.create({
   109→        model,
   110→        input: request.input,
   111→      });
   112→
   113→      return {
   114→        embeddings: response.data.map((d) => d.embedding),
   115→        model: response.model,
   116→        usage: {
   117→          promptTokens: response.usage.prompt_tokens,
   118→          totalTokens: response.usage.total_tokens,
   119→        },
   120→      };
   121→    } catch (error) {
   122→      const msg = error instanceof Error ? error.message : 'Unknown OpenAI error';
   123→      log.error('Embedding generation failed', { error: msg, model });
   124→      throw new ProviderError('openai', msg);
   125→    }
   126→  }
   127→
   128→  async healthCheck(): Promise<boolean> {
   129→    if (!env.OPENAI_API_KEY) return false;
   130→    try {
   131→      await this.client.models.list();
   132→      return true;
   133→    } catch {
   134→      return false;
   135→    }
   136→  }
   137→}
