     3→/**
     4→ * Validate and normalize a language code.
     5→ * Falls back to English if the code is unsupported.
     6→ */
     7→export function resolveLanguage(code: string | null | undefined): SupportedLanguage {
     8→  if (!code) return 'en';
     9→  const normalized = code.toLowerCase().trim().slice(0, 2);
    10→  if ((SUPPORTED_LANGUAGES as readonly string[]).includes(normalized)) {
    11→    return normalized as SupportedLanguage;
    12→  }
    13→  // Handle common variants
    14→  if (normalized === 'kr' || code.toLowerCase().startsWith('ht')) return 'ht';
    15→  return 'en';
    16→}
    17→
    18→/**
    19→ * Get display information for a language.
    20→ */
    21→export function getLanguageInfo(code: SupportedLanguage) {
    22→  return LANGUAGES[code];
    23→}
    24→
    25→/**
    26→ * Generate the language instruction for Sandra's system prompt.
    27→ */
    28→export function languagePromptInstruction(language: SupportedLanguage): string {
    29→  const info = LANGUAGES[language];
    30→  switch (language) {
    31→    case 'ht':
    32→      return `IMPORTANT: The user's preferred language is Haitian Creole (Kreyòl Ayisyen). You MUST respond in Haitian Creole. Be natural and conversational in Kreyòl.`;
    33→    case 'fr':
    34→      return `IMPORTANT: The user's preferred language is French (Français). You MUST respond in French. Be natural and conversational in French.`;
    35→    default:
