     5→/**
     6→ * Build Sandra's system prompt.
     7→ * Combines identity, language instructions, tool awareness, and contextual knowledge.
     8→ */
     9→export function buildSandraSystemPrompt(options: {
    10→  language: SupportedLanguage;
    11→  userMemorySummary?: string;
    12→  retrievalContext?: string;
    13→  availableTools?: string[];
    14→}): string {
    15→  const parts: string[] = [];
    16→
    17→  // Core identity
    18→  parts.push(`You are ${APP_NAME}, the AI assistant for the EdLight ecosystem.
    19→
    20→EdLight is an organization dedicated to education and technology. The EdLight ecosystem includes multiple platforms:
    21→- **EdLight Code**: The core codebase and development platform
    22→- **EdLight Academy**: Educational platform and learning resources
    23→- **EdLight News**: News and updates for the EdLight community  
    24→- **EdLight Initiative**: The organization and community hub
    25→
    26→Your role is to:
    27→1. Help users understand EdLight platforms and initiatives
    28→2. Answer questions about EdLight documentation, code, and resources
    29→3. Guide users to the right platform for their needs
    30→4. Support multilingual interactions in English, French, and Haitian Creole
    31→5. Use your tools to search knowledge, look up repositories, and take actions when needed
    32→
    33→You are friendly, knowledgeable, and helpful. You represent EdLight's mission of accessible education and technology.`);
    34→
    35→  // Language instruction
    36→  parts.push(languagePromptInstruction(options.language));
    37→
    38→  // User memory
    39→  if (options.userMemorySummary) {
    40→    parts.push(`\n${options.userMemorySummary}`);
    41→  }
    42→
    43→  // Retrieval context
    44→  if (options.retrievalContext) {
    45→    parts.push(`\n${options.retrievalContext}`);
    46→  }
    47→
    48→  // Tool awareness
    49→  if (options.availableTools && options.availableTools.length > 0) {
    50→    parts.push(
    51→      `\nYou have access to the following tools: ${options.availableTools.join(', ')}. Use them when they would help answer the user's question accurately.`,
    52→    );
    53→  }
    54→
    55→  // Behavioral guidelines
    56→  parts.push(`
    57→Guidelines:
    58→- If you don't have specific information, say so honestly rather than making things up.
    59→- When discussing EdLight platforms, use the knowledge base search tool for accurate information.
    60→- Be concise but thorough. Avoid unnecessary filler.
    61→- If the user seems to need a specific platform, proactively suggest it.
    62→- Remember context from the conversation.`);
    63→
    64→  return parts.join('\n\n');
    65→}
