     1→import type { AgentInput, AgentOutput, AgentConfig, AgentState } from './types';
     2→import { DEFAULT_AGENT_CONFIG } from './types';
     3→import { buildSandraSystemPrompt } from './prompts';
     4→import { getAIProvider } from '@/lib/ai';
     5→import type { ChatMessage } from '@/lib/ai/types';
     6→import { toolRegistry, executeTool } from '@/lib/tools';
     7→import { getSessionStore } from '@/lib/memory/session-store';
     8→import { getUserMemoryStore } from '@/lib/memory/user-memory';
     9→import { retrieveContext, formatRetrievalContext } from '@/lib/knowledge';
    10→import { createLogger } from '@/lib/utils';
    11→
    12→const log = createLogger('agents:sandra');
    13→
    14→/**
    15→ * Run the Sandra agent loop.
    16→ *
    17→ * Flow:
    18→ * 1. Load session memory (conversation history)
    19→ * 2. Load user memory (long-term facts)
    20→ * 3. Optionally retrieve relevant knowledge
    21→ * 4. Build system prompt
    22→ * 5. Call the LLM (with tools if enabled)
    23→ * 6. If tool calls are returned, execute them and loop
    24→ * 7. Return the final response
    25→ */
    26→export async function runSandraAgent(
    27→  input: AgentInput,
    28→  config?: Partial<AgentConfig>,
    29→): Promise<AgentOutput> {
    30→  const cfg = { ...DEFAULT_AGENT_CONFIG, ...config };
    31→  const provider = getAIProvider();
    32→  const sessionStore = getSessionStore();
    33→  const userMemoryStore = getUserMemoryStore();
    34→
    35→  log.info(`Agent invoked`, {
    36→    sessionId: input.sessionId,
    37→    language: input.language,
    38→    channel: input.channel,
    39→    messageLength: input.message.length,
    40→  });
    41→
    42→  // 1. Load conversation history
    43→  const historyMessages = await sessionStore.getContextMessages(input.sessionId);
    44→
    45→  // 2. Load user memory
    46→  let userMemorySummary = '';
    47→  if (input.userId) {
    48→    userMemorySummary = await userMemoryStore.getMemorySummary(input.userId);
    49→  }
    50→
    51→  // 3. Retrieval: search knowledge base for context
    52→  let retrievalContextStr = '';
    53→  if (cfg.enableRetrieval) {
    54→    try {
    55→      const results = await retrieveContext(input.message, { topK: 3, minScore: 0.5 });
    56→      if (results.length > 0) {
    57→        retrievalContextStr = formatRetrievalContext(results);
    58→      }
    59→    } catch (error) {
    60→      log.warn('Retrieval failed, continuing without context', {
    61→        error: error instanceof Error ? error.message : 'unknown',
    62→      });
    63→    }
    64→  }
    65→
    66→  // 4. Build system prompt
    67→  const toolDefinitions = cfg.enableTools ? toolRegistry.getToolDefinitions() : [];
    68→  const toolNames = cfg.enableTools ? toolRegistry.getToolNames() : [];
    69→
    70→  const systemPrompt = buildSandraSystemPrompt({
    71→    language: input.language,
    72→    userMemorySummary,
    73→    retrievalContext: retrievalContextStr,
    74→    availableTools: toolNames,
    75→  });
    76→
    77→  // 5. Assemble messages
    78→  const messages: ChatMessage[] = [
    79→    { role: 'system', content: systemPrompt },
    80→    ...historyMessages,
    81→    { role: 'user', content: input.message },
    82→  ];
    83→
    84→  // Save user message to session
    85→  await sessionStore.addEntry(input.sessionId, {
    86→    role: 'user',
    87→    content: input.message,
    88→    timestamp: new Date(),
    89→  });
    90→
    91→  // 6. Agent loop (handles tool calls)
    92→  const state: AgentState = {
    93→    messages,
    94→    toolCalls: [],
    95→    toolResults: new Map(),
    96→    retrievalContext: retrievalContextStr,
    97→    iterations: 0,
    98→    maxIterations: cfg.maxIterations,
    99→  };
   100→
   101→  const toolsUsed: string[] = [];
   102→  let totalUsage = { promptTokens: 0, completionTokens: 0, totalTokens: 0 };
   103→
   104→  while (state.iterations < state.maxIterations) {
   105→    state.iterations++;
   106→
   107→    const response = await provider.chatCompletion({
   108→      messages: state.messages,
   109→      tools: toolDefinitions.length > 0 ? toolDefinitions : undefined,
   110→      toolChoice: toolDefinitions.length > 0 ? 'auto' : undefined,
   111→      temperature: cfg.temperature,
   112→      maxTokens: cfg.maxTokens,
   113→    });
   114→
   115→    // Accumulate token usage
   116→    totalUsage.promptTokens += response.usage.promptTokens;
   117→    totalUsage.completionTokens += response.usage.completionTokens;
   118→    totalUsage.totalTokens += response.usage.totalTokens;
   119→
   120→    // If no tool calls, we have the final response
   121→    if (response.toolCalls.length === 0 || response.finishReason !== 'tool_calls') {
   122→      const content = response.content ?? 'I apologize, but I was unable to generate a response. Please try again.';
   123→
   124→      // Save assistant response to session
   125→      await sessionStore.addEntry(input.sessionId, {
   126→        role: 'assistant',
   127→        content,
   128→        timestamp: new Date(),
   129→      });
   130→
   131→      log.info(`Agent response generated`, {
   132→        sessionId: input.sessionId,
   133→        iterations: state.iterations,
   134→        toolsUsed,
   135→        totalTokens: totalUsage.totalTokens,
   136→      });
   137→
   138→      return {
   139→        response: content,
   140→        language: input.language,
   141→        toolsUsed,
   142→        retrievalUsed: retrievalContextStr.length > 0,
   143→        tokenUsage: totalUsage,
   144→      };
   145→    }
   146→
   147→    // Execute tool calls
   148→    // Add assistant message with tool calls to context
   149→    state.messages.push({
   150→      role: 'assistant',
   151→      content: response.content ?? '',
   152→    });
   153→
   154→    for (const toolCall of response.toolCalls) {
   155→      log.info(`Executing tool: ${toolCall.name}`, { id: toolCall.id });
   156→      toolsUsed.push(toolCall.name);
   157→
   158→      const result = await executeTool(toolCall.name, toolCall.arguments);
   159→      const resultStr = JSON.stringify(result.data ?? result.error ?? 'No result');
   160→
   161→      // Add tool result to messages
   162→      state.messages.push({
   163→        role: 'tool',
   164→        content: resultStr,
   165→        toolCallId: toolCall.id,
   166→        name: toolCall.name,
   167→      });
   168→
   169→      state.toolResults.set(toolCall.id, resultStr);
   170→    }
   171→  }
   172→
   173→  // Max iterations reached
   174→  log.warn(`Agent hit max iterations`, { sessionId: input.sessionId, iterations: state.iterations });
   175→
   176→  const fallback = 'I apologize, but I need more time to process your request. Could you try rephrasing your question?';
   177→
   178→  await sessionStore.addEntry(input.sessionId, {
   179→    role: 'assistant',
   180→    content: fallback,
   181→    timestamp: new Date(),
   182→  });
   183→
   184→  return {
   185→    response: fallback,
   186→    language: input.language,
   187→    toolsUsed,
   188→    retrievalUsed: retrievalContextStr.length > 0,
   189→    tokenUsage: totalUsage,
   190→  };
   191→}
