import { vi } from 'vitest';
import type {
  AIProvider,
  ChatCompletionRequest,
  ChatCompletionResponse,
  EmbeddingRequest,
  EmbeddingResponse,
} from '@/lib/ai/types';

/** Default canned chat completion response */
const defaultChatResponse: ChatCompletionResponse = {
  content: 'This is a mock response.',
  toolCalls: [],
  finishReason: 'stop',
  usage: {
    promptTokens: 10,
    completionTokens: 8,
    totalTokens: 18,
  },
  model: 'mock-model',
};

/** Default canned embedding response (1536-dim zero vector) */
const defaultEmbeddingResponse: EmbeddingResponse = {
  embeddings: [new Array(1536).fill(0) as number[]],
  model: 'mock-embedding-model',
  usage: {
    promptTokens: 5,
    totalTokens: 5,
  },
};

/**
 * Mock AIProvider implementing the AIProvider interface.
 * All methods are vi.fn() stubs with sensible default return values.
 */
export const mockAIProvider: AIProvider = {
  name: 'mock',

  chatCompletion: vi.fn(
    async (_request: ChatCompletionRequest): Promise<ChatCompletionResponse> =>
      ({ ...defaultChatResponse }),
  ),

  generateEmbeddings: vi.fn(
    async (_request: EmbeddingRequest): Promise<EmbeddingResponse> =>
      ({ ...defaultEmbeddingResponse }),
  ),

  healthCheck: vi.fn(async (): Promise<boolean> => true),
};

/** Reset all mock function call history between tests */
export function resetAIProviderMocks(): void {
  const chatMock = mockAIProvider.chatCompletion as ReturnType<typeof vi.fn>;
  const embedMock = mockAIProvider.generateEmbeddings as ReturnType<typeof vi.fn>;
  const healthMock = mockAIProvider.healthCheck as ReturnType<typeof vi.fn>;

  chatMock.mockReset();
  embedMock.mockReset();
  healthMock.mockReset();

  // Restore default implementations after reset
  chatMock.mockImplementation(
    async (_request: ChatCompletionRequest): Promise<ChatCompletionResponse> =>
      ({ ...defaultChatResponse }),
  );
  embedMock.mockImplementation(
    async (_request: EmbeddingRequest): Promise<EmbeddingResponse> =>
      ({ ...defaultEmbeddingResponse }),
  );
  healthMock.mockImplementation(async (): Promise<boolean> => true);
}

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

/**
 * Seed script for Sandra.
 * Populates the RepoRegistry with the default EdLight repositories.
 *
 * Run: npx prisma db seed
 */
async function main() {
  console.log('🌱 Seeding Sandra database...\n');

  // ── Repo Registry ──────────────────────────────────────────────────────────

  const repos = [
    {
      owner: 'edlinitiative',
      name: 'code',
      displayName: 'EdLight Code',
      description: 'The core EdLight codebase and platform.',
      url: 'https://github.com/edlinitiative/code',
      branch: 'main',
      docsPath: 'docs/',
      isActive: true,
    },
    {
      owner: 'edlinitiative',
      name: 'EdLight-News',
      displayName: 'EdLight News',
      description: 'News and updates platform for the EdLight community.',
      url: 'https://github.com/edlinitiative/EdLight-News',
      branch: 'main',
      docsPath: null,
      isActive: true,
    },
    {
      owner: 'edlinitiative',
      name: 'EdLight-Initiative',
      displayName: 'EdLight Initiative',
      description: 'The EdLight Initiative organization and community hub.',
      url: 'https://github.com/edlinitiative/EdLight-Initiative',
      branch: 'main',
      docsPath: null,
      isActive: true,
    },
    {
      owner: 'edlinitiative',
      name: 'EdLight-Academy',
      displayName: 'EdLight Academy',
      description: 'Educational platform and learning resources for the EdLight ecosystem.',
      url: 'https://github.com/edlinitiative/EdLight-Academy',
      branch: 'main',
      docsPath: 'docs/',
      isActive: true,
    },
  ];

  for (const repo of repos) {
    const result = await prisma.repoRegistry.upsert({
      where: { owner_name: { owner: repo.owner, name: repo.name } },
      create: repo,
      update: {
        displayName: repo.displayName,
        description: repo.description,
        url: repo.url,
        branch: repo.branch,
        docsPath: repo.docsPath,
        isActive: repo.isActive,
      },
    });
    console.log(`  ✅ Repo: ${result.displayName} (${result.owner}/${result.name})`);
  }

  // ── Default Admin User (optional) ──────────────────────────────────────────

  const adminUser = await prisma.user.upsert({
    where: { email: 'admin@edlight.org' },
    create: {
      name: 'Sandra Admin',
      email: 'admin@edlight.org',
      language: 'en',
      channel: 'web',
    },
    update: {},
  });
  console.log(`  ✅ Admin user: ${adminUser.name} (${adminUser.email})`);

  console.log('\n🌱 Seeding complete!\n');
}

main()
  .catch((e) => {
    console.error('❌ Seed failed:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

