     4→
     5→const LOG_LEVEL_PRIORITY: Record<LogLevel, number> = {
     6→  debug: 0,
     7→  info: 1,
     8→  warn: 2,
     9→  error: 3,
    10→};
    11→
    12→function shouldLog(level: LogLevel): boolean {
    13→  return LOG_LEVEL_PRIORITY[level] >= LOG_LEVEL_PRIORITY[env.LOG_LEVEL];
    14→}
    15→
    16→function formatMessage(level: LogLevel, context: string, message: string, meta?: Record<string, unknown>): string {
    17→  const timestamp = new Date().toISOString();
    18→  const metaStr = meta ? ` ${JSON.stringify(meta)}` : '';
    19→  return `[${timestamp}] [${level.toUpperCase()}] [${context}] ${message}${metaStr}`;
    20→}
    21→
    22→/**
    23→ * Lightweight structured logger.
    24→ * Outputs to console; replace with a transport (e.g., Pino) for production.
    25→ */
    26→export function createLogger(context: string) {
