     1→import { toolRegistry } from './registry';
     2→import type { ToolResult } from './types';
     3→import { createLogger, ToolExecutionError } from '@/lib/utils';
     4→
     5→const log = createLogger('tools:executor');
     6→
     7→/**
     8→ * Execute a tool by name with the given arguments (JSON string).
     9→ * Validates input, runs the tool, and returns a structured result.
    10→ */
    11→export async function executeTool(name: string, argsJson: string): Promise<ToolResult> {
    12→  const tool = toolRegistry.get(name);
    13→
    14→  if (!tool) {
    15→    log.error(`Tool not found: ${name}`);
    16→    return { success: false, data: null, error: `Tool '${name}' not found` };
    17→  }
    18→
    19→  try {
    20→    // Parse arguments
    21→    let parsedArgs: unknown;
    22→    try {
    23→      parsedArgs = JSON.parse(argsJson);
    24→    } catch {
    25→      return { success: false, data: null, error: `Invalid JSON arguments for tool '${name}'` };
    26→    }
    27→
    28→    // Validate with Zod schema
    29→    const validated = tool.inputSchema.safeParse(parsedArgs);
    30→    if (!validated.success) {
    31→      const issues = validated.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
    32→      return { success: false, data: null, error: `Validation failed for tool '${name}': ${issues}` };
    33→    }
    34→
    35→    log.info(`Executing tool: ${name}`, { args: parsedArgs });
    36→    const result = await tool.execute(validated.data);
    37→    log.info(`Tool ${name} completed`, { success: result.success });
    38→
    39→    return result;
    40→  } catch (error) {
    41→    const msg = error instanceof Error ? error.message : 'Unknown error';
    42→    log.error(`Tool execution failed: ${name}`, { error: msg });
    43→    throw new ToolExecutionError(name, msg);
    44→  }
    45→}
