     1→/**
     2→ * Structured error types for Sandra.
     3→ * Provides consistent error handling across the platform.
     4→ */
     5→
     6→export type ErrorCode =
     7→  | 'VALIDATION_ERROR'
     8→  | 'AUTH_ERROR'
     9→  | 'NOT_FOUND'
    10→  | 'UNAUTHORIZED'
    11→  | 'FORBIDDEN'
    12→  | 'RATE_LIMITED'
    13→  | 'PROVIDER_ERROR'
    14→  | 'TOOL_ERROR'
    15→  | 'INTERNAL_ERROR'
    16→  | 'CONFIGURATION_ERROR'
    17→  | 'TOOL_EXECUTION_ERROR'
    18→  | 'CHANNEL_ERROR'
    19→  | 'INDEXING_ERROR';
    20→
    21→export class SandraError extends Error {
    22→  public readonly code: ErrorCode;
    23→  public readonly statusCode: number;
    24→  public readonly details?: Record<string, unknown>;
    25→
    26→  constructor(
    27→    message: string,
    28→    code: ErrorCode = 'INTERNAL_ERROR',
    29→    statusCode = 500,
    30→    details?: Record<string, unknown>,
    31→  ) {
    32→    super(message);
    33→    this.name = 'SandraError';
    34→    this.code = code;
    35→    this.statusCode = statusCode;
    36→    this.details = details;
    37→  }
    38→
    39→  toJSON() {
    40→    return {
    41→      error: {
    42→        code: this.code,
    43→        message: this.message,
    44→        ...(this.details ? { details: this.details } : {}),
    45→      },
    46→    };
    47→  }
    48→}
    49→
    50→export class ValidationError extends SandraError {
    51→  constructor(message: string, details?: Record<string, unknown>) {
    52→    super(message, 'VALIDATION_ERROR', 400, details);
    53→    this.name = 'ValidationError';
    54→  }
    55→}
    56→
    57→export class AuthError extends SandraError {
    58→  constructor(message: string, details?: Record<string, unknown>) {
    59→    super(message, 'AUTH_ERROR', 401, details);
    60→    this.name = 'AuthError';
    61→  }
    62→}
    63→
    64→export class NotFoundError extends SandraError {
    65→  constructor(resource: string, id?: string) {
    66→    super(
    67→      id ? `${resource} with id '${id}' not found` : `${resource} not found`,
    68→      'NOT_FOUND',
    69→      404,
    70→    );
    71→    this.name = 'NotFoundError';
    72→  }
    73→}
    74→
    75→export class ProviderError extends SandraError {
    76→  constructor(provider: string, message: string, details?: Record<string, unknown>) {
    77→    super(`[${provider}] ${message}`, 'PROVIDER_ERROR', 502, details);
    78→    this.name = 'ProviderError';
    79→  }
    80→}
    81→
    82→export class ToolError extends SandraError {
    83→  constructor(toolName: string, message: string, details?: Record<string, unknown>) {
    84→    super(`Tool '${toolName}' failed: ${message}`, 'TOOL_ERROR', 500, details);
    85→    this.name = 'ToolError';
    86→  }
    87→}
    88→
    89→export class ConfigurationError extends SandraError {
    90→  constructor(message: string) {
    91→    super(message, 'CONFIGURATION_ERROR', 500);
    92→    this.name = 'ConfigurationError';
    93→  }
    94→}
    95→
    96→export class ToolExecutionError extends SandraError {
    97→  constructor(toolName: string, message: string, details?: Record<string, unknown>) {
    98→    super(`Tool '${toolName}' failed: ${message}`, 'TOOL_EXECUTION_ERROR', 500, details);
    99→    this.name = 'ToolExecutionError';
   100→  }
   101→}
   102→
   103→/**
   104→ * Wrap an async operation with structured error handling.
   105→ */
   106→export async function withErrorHandling<T>(
   107→  operation: () => Promise<T>,
   108→  context: string,
   109→): Promise<T> {
   110→  try {
   111→    return await operation();
   112→  } catch (error) {
   113→    if (error instanceof SandraError) throw error;
   114→    const message = error instanceof Error ? error.message : 'Unknown error';
   115→    throw new SandraError(`${context}: ${message}`, 'INTERNAL_ERROR', 500);
   116→  }
   117→}
   118→
   119→/**
   120→ * Create a structured API error response.
   121→ */
   122→export function errorResponse(error: unknown): { error: { code: ErrorCode; message: string }; status: number } {
   123→  if (error instanceof SandraError) {
   124→    return { error: { code: error.code, message: error.message }, status: error.statusCode };
   125→  }
   126→  const message = error instanceof Error ? error.message : 'An unexpected error occurred';
   127→  return { error: { code: 'INTERNAL_ERROR', message }, status: 500 };
   128→}
