     1→import { createHash } from 'crypto';
     2→import { DEFAULT_CHUNK_SIZE, DEFAULT_CHUNK_OVERLAP } from '@/lib/config';
     3→import type { RawDocument, DocumentChunk } from './types';
     4→
     5→/**
     6→ * Split a document into overlapping chunks.
     7→ * Uses a simple character-based strategy with paragraph awareness.
     8→ */
     9→export function chunkDocument(
    10→  doc: RawDocument,
    11→  options?: { chunkSize?: number; chunkOverlap?: number },
    12→): DocumentChunk[] {
    13→  const chunkSize = options?.chunkSize ?? DEFAULT_CHUNK_SIZE;
    14→  const overlap = options?.chunkOverlap ?? DEFAULT_CHUNK_OVERLAP;
    15→
    16→  const text = doc.content.trim();
    17→  if (!text) return [];
    18→
    19→  // If the document fits in one chunk, return it as-is
    20→  if (text.length <= chunkSize) {
    21→    return [
    22→      {
    23→        sourceId: doc.sourceId,
    24→        documentId: doc.id,
    25→        title: doc.title,
    26→        path: doc.path,
    27→        content: text,
    28→        chunkIndex: 0,
    29→        chunkTotal: 1,
    30→        contentHash: hashContent(text),
    31→        metadata: doc.metadata,
    32→      },
    33→    ];
    34→  }
    35→
    36→  // Split into paragraphs first, then recombine into chunks
    37→  const paragraphs = text.split(/\n\s*\n/).filter((p) => p.trim().length > 0);
    38→  const chunks: string[] = [];
    39→  let current = '';
    40→
    41→  for (const para of paragraphs) {
    42→    if (current.length + para.length + 2 > chunkSize && current.length > 0) {
    43→      chunks.push(current.trim());
    44→      // Keep overlap from end of current chunk
    45→      const overlapText = current.slice(-overlap);
    46→      current = overlapText + '\n\n' + para;
    47→    } else {
    48→      current = current ? current + '\n\n' + para : para;
    49→    }
    50→  }
    51→  if (current.trim()) {
    52→    chunks.push(current.trim());
    53→  }
    54→
    55→  // If paragraph-based chunking produced only one chunk but text is long,
    56→  // fall back to character-based splitting
    57→  if (chunks.length === 1 && text.length > chunkSize) {
    58→    return chunkByCharacters(doc, text, chunkSize, overlap);
    59→  }
    60→
    61→  return chunks.map((content, index) => ({
    62→    sourceId: doc.sourceId,
    63→    documentId: doc.id,
    64→    title: doc.title,
    65→    path: doc.path,
    66→    content,
    67→    chunkIndex: index,
    68→    chunkTotal: chunks.length,
    69→    contentHash: hashContent(content),
    70→    metadata: doc.metadata,
    71→  }));
    72→}
    73→
    74→function chunkByCharacters(
    75→  doc: RawDocument,
    76→  text: string,
    77→  chunkSize: number,
    78→  overlap: number,
    79→): DocumentChunk[] {
    80→  const chunks: string[] = [];
    81→  let start = 0;
    82→
    83→  while (start < text.length) {
    84→    const end = Math.min(start + chunkSize, text.length);
    85→    chunks.push(text.slice(start, end));
    86→    start = end - overlap;
    87→    if (start >= text.length) break;
    88→  }
    89→
    90→  return chunks.map((content, index) => ({
    91→    sourceId: doc.sourceId,
    92→    documentId: doc.id,
    93→    title: doc.title,
    94→    path: doc.path,
    95→    content,
    96→    chunkIndex: index,
    97→    chunkTotal: chunks.length,
    98→    contentHash: hashContent(content),
    99→    metadata: doc.metadata,
   100→  }));
   101→}
   102→
   103→function hashContent(content: string): string {
   104→  return createHash('sha256').update(content).digest('hex').slice(0, 16);
   105→}
