     6→
     7→/**
     8→ * Generate embeddings for document chunks using the configured AI provider.
     9→ */
    10→export async function embedChunks(
    11→  chunks: DocumentChunk[],
    12→  batchSize = 20,
    13→): Promise<EmbeddedChunk[]> {
    14→  if (chunks.length === 0) return [];
    15→
    16→  const provider = getAIProvider();
    17→  const results: EmbeddedChunk[] = [];
    18→
    19→  // Process in batches to respect API rate limits
    20→  for (let i = 0; i < chunks.length; i += batchSize) {
    21→    const batch = chunks.slice(i, i + batchSize);
    22→    const texts = batch.map((c) => c.content);
    23→
    24→    log.debug(`Embedding batch ${i / batchSize + 1}, size=${batch.length}`);
    25→
    26→    const response = await provider.generateEmbeddings({ input: texts });
    27→
    28→    for (let j = 0; j < batch.length; j++) {
    29→      const chunk = batch[j]!;
    30→      const embedding = response.embeddings[j];
    31→      if (!embedding) {
    32→        log.warn(`Missing embedding for chunk ${i + j}`);
    33→        continue;
    34→      }
    35→      results.push({ ...chunk, embedding });
    36→    }
    37→  }
    38→
    39→  log.info(`Embedded ${results.length} chunks`);
    40→  return results;
    41→}
    42→
    43→/**
    44→ * Generate a single embedding for a query string.
    45→ */
    46→export async function embedQuery(query: string): Promise<number[]> {
    47→  const provider = getAIProvider();
    48→  const response = await provider.generateEmbeddings({ input: query });
    49→  const embedding = response.embeddings[0];
    50→  if (!embedding) throw new Error('Failed to generate query embedding');
    51→  return embedding;
    52→}
