     1→import type { VectorStore, EmbeddedChunk, SearchResult, DocumentChunk } from './types';
     2→import { DEFAULT_TOP_K } from '@/lib/config';
     3→import { createLogger } from '@/lib/utils';
     4→
     5→const log = createLogger('knowledge:vectorstore');
     6→
     7→/**
     8→ * In-memory vector store implementation.
     9→ * Uses brute-force cosine similarity — fine for development and small datasets.
    10→ * Replace with Pinecone, Qdrant, or pgvector for production.
    11→ */
    12→export class InMemoryVectorStore implements VectorStore {
    13→  private entries: EmbeddedChunk[] = [];
    14→
    15→  async upsert(chunks: EmbeddedChunk[]): Promise<void> {
    16→    for (const chunk of chunks) {
    17→      // Deduplicate by content hash
    18→      const existing = this.entries.findIndex(
    19→        (e) => e.sourceId === chunk.sourceId && e.contentHash === chunk.contentHash,
    20→      );
    21→      if (existing >= 0) {
    22→        this.entries[existing] = chunk;
    23→      } else {
    24→        this.entries.push(chunk);
    25→      }
    26→    }
    27→    log.info(`Upserted ${chunks.length} chunks, total=${this.entries.length}`);
    28→  }
    29→
    30→  async search(query: number[], topK?: number, filter?: Record<string, unknown>): Promise<SearchResult[]> {
    31→    const k = topK ?? DEFAULT_TOP_K;
    32→
    33→    let candidates = this.entries;
    34→    if (filter?.sourceId) {
    35→      candidates = candidates.filter((e) => e.sourceId === filter.sourceId);
    36→    }
    37→
    38→    const scored = candidates.map((entry) => ({
    39→      chunk: stripEmbedding(entry),
    40→      score: cosineSimilarity(query, entry.embedding),
    41→    }));
    42→
    43→    scored.sort((a, b) => b.score - a.score);
    44→    return scored.slice(0, k);
    45→  }
    46→
    47→  async deleteBySource(sourceId: string): Promise<void> {
    48→    const before = this.entries.length;
    49→    this.entries = this.entries.filter((e) => e.sourceId !== sourceId);
    50→    log.info(`Deleted chunks for source ${sourceId}: ${before - this.entries.length} removed`);
    51→  }
    52→
    53→  async count(sourceId?: string): Promise<number> {
    54→    if (sourceId) {
    55→      return this.entries.filter((e) => e.sourceId === sourceId).length;
    56→    }
    57→    return this.entries.length;
    58→  }
    59→
    60→  async isReady(): Promise<boolean> {
    61→    return true;
    62→  }
    63→}
    64→
    65→function stripEmbedding(chunk: EmbeddedChunk): DocumentChunk {
    66→  const { embedding: _embedding, ...rest } = chunk;
    67→  return rest;
    68→}
    69→
    70→function cosineSimilarity(a: number[], b: number[]): number {
    71→  if (a.length !== b.length) return 0;
    72→  let dotProduct = 0;
    73→  let normA = 0;
    74→  let normB = 0;
    75→  for (let i = 0; i < a.length; i++) {
    76→    dotProduct += a[i]! * b[i]!;
    77→    normA += a[i]! * a[i]!;
    78→    normB += b[i]! * b[i]!;
    79→  }
    80→  const denominator = Math.sqrt(normA) * Math.sqrt(normB);
    81→  if (denominator === 0) return 0;
    82→  return dotProduct / denominator;
    83→}
