     7→const log = createLogger('knowledge:retrieval');
     8→
     9→/**
    10→ * High-level retrieval service.
    11→ * Embeds a query and searches the vector store.
    12→ */
    13→export async function retrieveContext(
    14→  query: string,
    15→  options?: {
    16→    topK?: number;
    17→    sourceId?: string;
    18→    minScore?: number;
    19→  },
    20→): Promise<SearchResult[]> {
    21→  const topK = options?.topK ?? DEFAULT_TOP_K;
    22→  const minScore = options?.minScore ?? 0.5;
    23→
    24→  try {
    25→    const queryEmbedding = await embedQuery(query);
    26→    const store = getVectorStore();
    27→
    28→    const filter = options?.sourceId ? { sourceId: options.sourceId } : undefined;
    29→    const results = await store.search(queryEmbedding, topK, filter);
    30→
    31→    // Filter by minimum score
    32→    const filtered = results.filter((r) => r.score >= minScore);
    33→
    34→    log.info(`Retrieved ${filtered.length} results for query`, {
    35→      query: query.slice(0, 80),
    36→      topK,
    37→      minScore,
    38→      totalResults: results.length,
    39→      filteredResults: filtered.length,
    40→    });
    41→
    42→    return filtered;
    43→  } catch (error) {
    44→    log.error('Retrieval failed', {
    45→      error: error instanceof Error ? error.message : 'Unknown error',
    46→    });
    47→    return [];
    48→  }
    49→}
    50→
    51→/**
    52→ * Format retrieval results into a context string for the LLM.
    53→ */
    54→export function formatRetrievalContext(results: SearchResult[]): string {
    55→  if (results.length === 0) return '';
    56→
    57→  const sections = results.map((r, i) => {
    58→    const header = r.chunk.title ? `[${r.chunk.title}]` : `[Document ${i + 1}]`;
    59→    const source = r.chunk.path ? ` (${r.chunk.path})` : '';
    60→    return `${header}${source}\n${r.chunk.content}`;
    61→  });
    62→
    63→  return `Relevant context from EdLight knowledge base:\n\n${sections.join('\n\n---\n\n')}`;
    64→}
