     9→/**
    10→ * Ingest raw documents into the knowledge base.
    11→ * Chunks → embeds → stores in vector store.
    12→ */
    13→export async function ingestDocuments(
    14→  documents: RawDocument[],
    15→  options?: { chunkSize?: number; chunkOverlap?: number },
    16→): Promise<{ totalChunks: number; totalDocuments: number }> {
    17→  log.info(`Ingesting ${documents.length} documents`);
    18→
    19→  // 1. Chunk all documents
    20→  const allChunks = documents.flatMap((doc) => chunkDocument(doc, options));
    21→  log.info(`Chunked into ${allChunks.length} chunks`);
    22→
    23→  if (allChunks.length === 0) {
    24→    return { totalChunks: 0, totalDocuments: documents.length };
    25→  }
    26→
    27→  // 2. Generate embeddings
    28→  const embedded: EmbeddedChunk[] = await embedChunks(allChunks);
    29→
    30→  // 3. Store in vector store
    31→  const store = getVectorStore();
    32→  await store.upsert(embedded);
    33→
    34→  log.info(`Ingestion complete: ${embedded.length} chunks stored`);
    35→  return { totalChunks: embedded.length, totalDocuments: documents.length };
    36→}
    37→
    38→/**
    39→ * Remove all indexed content for a source.
    40→ */
    41→export async function removeSource(sourceId: string): Promise<void> {
    42→  const store = getVectorStore();
    43→  await store.deleteBySource(sourceId);
    44→  log.info(`Removed all content for source: ${sourceId}`);
    45→}
