     1→import type { PrismaClient, Prisma } from '@prisma/client';
     2→import type { ChatMessage } from '@/lib/ai/types';
     3→import type { SessionMemoryStore, ConversationEntry } from './types';
     4→import { MAX_CONTEXT_MESSAGES } from '@/lib/config';
     5→import { createLogger } from '@/lib/utils';
     6→
     7→const log = createLogger('memory:prisma-session');
     8→
     9→/**
    10→ * Prisma-backed session memory store.
    11→ * Persists conversation history to the Message table via PostgreSQL.
    12→ *
    13→ * Usage:
    14→ *   import { db } from '@/lib/db';
    15→ *   import { PrismaSessionStore } from '@/lib/memory/prisma-session-store';
    16→ *   setSessionStore(new PrismaSessionStore(db));
    17→ */
    18→export class PrismaSessionStore implements SessionMemoryStore {
    19→  constructor(private readonly prisma: PrismaClient) {}
    20→
    21→  async getHistory(sessionId: string, limit?: number): Promise<ConversationEntry[]> {
    22→    // Ensure the session exists
    23→    await this.ensureSession(sessionId);
    24→
    25→    const messages = await this.prisma.message.findMany({
    26→      where: { sessionId },
    27→      orderBy: { createdAt: 'asc' },
    28→      ...(limit ? { take: limit, skip: undefined } : {}),
    29→    });
    30→
    31→    // If we need the *last N*, we must fetch desc then reverse
    32→    if (limit && messages.length > limit) {
    33→      return messages.slice(-limit).map(this.toEntry);
    34→    }
    35→
    36→    return messages.map(this.toEntry);
    37→  }
    38→
    39→  async addEntry(sessionId: string, entry: ConversationEntry): Promise<void> {
    40→    await this.ensureSession(sessionId);
    41→
    42→    await this.prisma.message.create({
    43→      data: {
    44→        sessionId,
    45→        role: entry.role,
    46→        content: entry.content,
    47→        language: (entry.metadata?.['language'] as string) ?? undefined,
    48→        toolName: (entry.metadata?.['toolName'] as string) ?? undefined,
    49→        toolCallId: (entry.metadata?.['toolCallId'] as string) ?? undefined,
    50→        metadata: entry.metadata
    51→          ? (entry.metadata as Prisma.InputJsonValue)
    52→          : undefined,
    53→        createdAt: entry.timestamp,
    54→      },
    55→    });
    56→
    57→    // Update session last-active timestamp
    58→    await this.prisma.session.update({
    59→      where: { id: sessionId },
    60→      data: { updatedAt: new Date() },
    61→    });
    62→
    63→    log.debug(`Persisted entry to session ${sessionId}`, { role: entry.role });
    64→  }
    65→
    66→  async getContextMessages(sessionId: string, limit?: number): Promise<ChatMessage[]> {
    67→    const max = limit ?? MAX_CONTEXT_MESSAGES;
    68→
    69→    const messages = await this.prisma.message.findMany({
    70→      where: {
    71→        sessionId,
    72→        role: { in: ['user', 'assistant', 'system', 'tool'] },
    73→      },
    74→      orderBy: { createdAt: 'desc' },
    75→      take: max,
    76→      select: { role: true, content: true },
    77→    });
    78→
    79→    // Reverse to get chronological order
    80→    return messages.reverse().map((m) => ({
    81→      role: m.role as ChatMessage['role'],
    82→      content: m.content,
    83→    }));
    84→  }
    85→
    86→  async clear(sessionId: string): Promise<void> {
    87→    await this.prisma.message.deleteMany({ where: { sessionId } });
    88→    log.debug(`Cleared session memory: ${sessionId}`);
    89→  }
    90→
    91→  // ── Helpers ──────────────────────────────────────────────────────────────
    92→
    93→  private toEntry(msg: { role: string; content: string; createdAt: Date; metadata: unknown }): ConversationEntry {
    94→    return {
    95→      role: msg.role as ConversationEntry['role'],
    96→      content: msg.content,
    97→      timestamp: msg.createdAt,
    98→      metadata: (msg.metadata as Record<string, unknown>) ?? undefined,
    99→    };
   100→  }
   101→
   102→  /**
   103→   * Auto-create the Session row if it doesn't exist.
   104→   * This avoids FK violations when the first message arrives
   105→   * before an explicit session creation flow.
   106→   */
   107→  private async ensureSession(sessionId: string): Promise<void> {
   108→    const existing = await this.prisma.session.findUnique({
   109→      where: { id: sessionId },
   110→      select: { id: true },
   111→    });
   112→
   113→    if (!existing) {
   114→      await this.prisma.session.create({
   115→        data: { id: sessionId },
   116→      });
   117→      log.debug(`Auto-created session: ${sessionId}`);
   118→    }
   119→  }
   120→}
