    37→    await this.prisma.memory.upsert({
    38→      where: { userId_key: { userId, key: entry.key } },
    39→      create: {
    40→        userId,
    41→        key: entry.key,
    42→        value: entry.value,
    43→        source: entry.source,
    44→        confidence: entry.confidence,
    45→      },
    46→      update: {
    47→        value: entry.value,
    48→        source: entry.source,
    49→        confidence: entry.confidence,
    50→      },
    51→    });
    52→
    53→    log.debug(`Saved user memory: ${userId}/${entry.key}`);
    54→  }
    55→
    56→  async deleteMemory(userId: string, key: string): Promise<void> {
    57→    await this.prisma.memory.deleteMany({
    58→      where: { userId, key },
    59→    });
    60→
    61→    log.debug(`Deleted user memory: ${userId}/${key}`);
    62→  }
    63→
    64→  async getMemorySummary(userId: string): Promise<string> {
    65→    const memories = await this.getMemories(userId);
    66→    if (memories.length === 0) return '';
    67→
    68→    const lines = memories
    69→      .filter((m) => m.confidence >= 0.5) // Only include confident memories
    70→      .map((m) => `- ${m.key}: ${m.value}`);
    71→
    72→    if (lines.length === 0) return '';
    73→    return `Known facts about the user:\n${lines.join('\n')}`;
    74→  }
    75→
    76→  // ── Helpers ──────────────────────────────────────────────────────────────
    77→
    78→  private toEntry(row: {
    79→    key: string;
    80→    value: string;
    81→    source: string | null;
    82→    confidence: number;
    83→    updatedAt: Date;
    84→  }): UserMemoryEntry {
    85→    return {
    86→      key: row.key,
    87→      value: row.value,
    88→      source: row.source ?? 'unknown',
    89→      confidence: row.confidence,
    90→      updatedAt: row.updatedAt,
    91→    };
    92→  }
    93→}
