import type { ToolResult, ToolContext } from './types';
import { createLogger, AuthError, ValidationError } from '@/lib/utils';

const log = createLogger('tools:executor');

const DEFAULT_CONTEXT: ToolContext = { sessionId: '', scopes: [] };

/**
 * Execute a tool by name with the given arguments (JSON string).
 * Validates input, checks permission scopes, runs the tool, and returns a structured result.
 */
export async function executeTool(
  name: string,
  argsJson: string,
  context: ToolContext = DEFAULT_CONTEXT,
): Promise<ToolResult> {
  const tool = toolRegistry.get(name);

  if (!tool) {
    log.error(`Tool not found: ${name}`);
    return { success: false, data: null, error: `Tool '${name}' not found` };
  }

  // Check permission scopes
  const requiredScopes = tool.requiredScopes ?? [];
  const missingScopes = requiredScopes.filter((s) => !context.scopes.includes(s));
  if (missingScopes.length > 0) {
    throw new AuthError(`Missing required scopes for tool '${name}': ${missingScopes.join(', ')}`);
  }

  // Parse arguments
  let parsedArgs: unknown;
  try {
    parsedArgs = JSON.parse(argsJson);
  } catch {
    return { success: false, data: null, error: `Invalid JSON arguments for tool '${name}'` };
  }

  // Validate with Zod schema
  const validated = tool.inputSchema.safeParse(parsedArgs);
  if (!validated.success) {
    const issues = validated.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
    throw new ValidationError(`Validation failed for tool '${name}': ${issues}`);
  }

  const start = Date.now();
  try {
    log.info(`Executing tool: ${name}`, { args: parsedArgs });
    const result = await tool.execute(validated.data);
    log.info(`Tool ${name} completed in ${Date.now() - start}ms`, { success: result.success });
    return result;
