import { z } from 'zod';
import type { SandraTool, ToolResult } from './types';
import { toolRegistry } from './registry';
import { db } from '@/lib/db';
import { getActiveRepos, getRepoByOwnerAndName } from '@/lib/db/repos';

const inputSchema = z.object({
  repoName: z.string().optional().describe('Filter by repository name (partial match supported)'),
});

const lookupRepoInfo: SandraTool = {
  name: 'lookupRepoInfo',
  description:
    'Look up information about EdLight GitHub repositories. Returns metadata, description, and indexing status. If repoName is provided, filters to matching repos; otherwise returns all active repos.',
  parameters: {
    type: 'object',
    properties: {
      repoName: { type: 'string', description: 'Filter by repository name (optional)' },
    },
    required: [],
  },
  inputSchema,
  requiredScopes: ['repos:read'],

  async execute(input: unknown): Promise<ToolResult> {
    const params = inputSchema.parse(input);

    if (params.repoName) {
      // Try exact owner/name match first (split on '/')
      const parts = params.repoName.split('/');
      if (parts.length === 2) {
        const [owner, name] = parts;
        const repo = await getRepoByOwnerAndName(db, owner!, name!);
        if (repo) {
          return {
            success: true,
            data: {
              repos: [
                {
                  name: repo.name,
                  displayName: repo.displayName,
                  description: repo.description,
                  url: repo.url,
                  syncStatus: repo.syncStatus,
                },
              ],
            },
          };
        }
      }

      // Otherwise filter active repos by name
      const allRepos = await getActiveRepos(db);
      const filtered = allRepos.filter(
        (r) =>
          r.name.toLowerCase().includes(params.repoName!.toLowerCase()) ||
          (r.displayName ?? '').toLowerCase().includes(params.repoName!.toLowerCase()),
      );
      return {
        success: true,
        data: {
          repos: filtered.map((r) => ({
            name: r.name,
            displayName: r.displayName,
            description: r.description,
            url: r.url,
            syncStatus: r.syncStatus,
          })),
        },
      };
    }

    // Return all active repos
    const repos = await getActiveRepos(db);
    return {
      success: true,
      data: {
        repos: repos.map((r) => ({
          name: r.name,
          displayName: r.displayName,
          description: r.description,
          url: r.url,
          syncStatus: r.syncStatus,
        })),
      },
    };
  },
};

toolRegistry.register(lookupRepoInfo);

export { lookupRepoInfo };

