import type { ChatMessage } from '@/lib/ai/types';
import type { SessionMemoryStore, ConversationEntry } from './types';
import { MAX_CONTEXT_MESSAGES } from '@/lib/config';
import { createLogger } from '@/lib/utils';
import { db } from '@/lib/db';
import {
  createSession as dbCreateSession,
  getSessionById,
  updateSession as dbUpdateSession,
  type CreateSessionInput,
  type UpdateSessionInput,
} from '@/lib/db/sessions';
import { createMessage, getMessagesBySessionId, type CreateMessageInput } from '@/lib/db/messages';
import type { Session, Message } from '@prisma/client';

const log = createLogger('memory:session');

/**
 * In-memory session store.
 * Production replacement: backed by Redis or Postgres.
 */
export class InMemorySessionStore implements SessionMemoryStore {
  private store = new Map<string, ConversationEntry[]>();

  async getHistory(sessionId: string, limit?: number): Promise<ConversationEntry[]> {
    const entries = this.store.get(sessionId) ?? [];
    if (limit) return entries.slice(-limit);
    return entries;
  }

  async addEntry(sessionId: string, entry: ConversationEntry): Promise<void> {
    const entries = this.store.get(sessionId) ?? [];
    entries.push(entry);
    this.store.set(sessionId, entries);
    log.debug(`Added entry to session ${sessionId}`, { role: entry.role });
  }

  async getContextMessages(sessionId: string, limit?: number): Promise<ChatMessage[]> {
    const max = limit ?? MAX_CONTEXT_MESSAGES;
    const entries = await this.getHistory(sessionId, max);
    return entries.map((e) => ({
      role: e.role,
      content: e.content,
    }));
  }

  async clear(sessionId: string): Promise<void> {
    this.store.delete(sessionId);
    log.debug(`Cleared session memory: ${sessionId}`);
  }
}

// Singleton for the default session store
let sessionStore: SessionMemoryStore | null = null;

export function getSessionStore(): SessionMemoryStore {
  if (!sessionStore) {
    sessionStore = new InMemorySessionStore();
  }
  return sessionStore;
}

export function setSessionStore(store: SessionMemoryStore): void {
  sessionStore = store;
}

// ── Session Service ──────────────────────────────────────────────────────────

/**
 * Higher-level session management service.
 * Wraps data access helpers with business logic for session lifecycle,
 * message persistence, and context loading.
 */
export class SessionService {
  /**
   * Create a new session. Defaults: language='en', channel='web', isActive=true.
   */
  async createSession(params: CreateSessionInput): Promise<Session> {
    const session = await dbCreateSession(db, params);
    log.info(`Created session ${session.id}`, { channel: session.channel });
    return session;
  }

  /** Get a session by ID, or null if not found. */
  async getSession(sessionId: string): Promise<Session | null> {
    return getSessionById(db, sessionId);
  }

  /** Update session fields (language, title, isActive). */
  async updateSession(sessionId: string, updates: UpdateSessionInput): Promise<Session> {
    const session = await dbUpdateSession(db, sessionId, updates);
    log.debug(`Updated session ${sessionId}`);
    return session;
  }

  /**
   * Persist a message to the session.
   */
  async addMessage(params: CreateMessageInput): Promise<Message> {
    const msg = await createMessage(db, params);
    log.debug(`Added message to session ${params.sessionId}`, { role: params.role });
    return msg;
  }

  /**
   * Get messages for a session with optional limit and ordering.
   */
  async getMessages(
    sessionId: string,
    options: { limit?: number; order?: 'asc' | 'desc' } = {},
  ): Promise<Message[]> {
    return getMessagesBySessionId(db, sessionId, {
      limit: options.limit,
      orderBy: options.order ?? 'asc',
    });
  }

  /**
   * Load the most recent N messages as ChatMessage[] for the LLM.
   * Returns messages in chronological (oldest-first) order.
   */
  async loadContext(sessionId: string, maxMessages?: number): Promise<ChatMessage[]> {
    const limit = maxMessages ?? MAX_CONTEXT_MESSAGES;

    // Fetch last N messages ordered DESC, then reverse for chronological order
    const messages = await getMessagesBySessionId(db, sessionId, {
      limit,
      orderBy: 'desc',
    });

    return messages.reverse().map((m) => {
      const base: ChatMessage = {
        role: m.role as ChatMessage['role'],
        content: m.content,
      };
      if (m.toolCallId) {
        base.toolCallId = m.toolCallId;
      }
      if (m.toolName) {
        base.name = m.toolName;
      }
      return base;
    });
  }
}

// Singleton
let sessionService: SessionService | null = null;

export function getSessionService(): SessionService {
  if (!sessionService) {
    sessionService = new SessionService();
  }
  return sessionService;
}

