import { createHash } from 'crypto';
import { DEFAULT_CHUNK_SIZE, DEFAULT_CHUNK_OVERLAP } from '@/lib/config';
import type { RawDocument, DocumentChunk } from './types';

/**
 * Split a document into overlapping chunks with heading context awareness.
 * Splits on markdown headings first, then paragraphs, then falls back to characters.
 */
export function chunkDocument(
  doc: RawDocument,
  options?: { chunkSize?: number; chunkOverlap?: number },
): DocumentChunk[] {
  const chunkSize = options?.chunkSize ?? DEFAULT_CHUNK_SIZE;
  const overlap = options?.chunkOverlap ?? DEFAULT_CHUNK_OVERLAP;

  const text = doc.content.trim();
  if (!text) return [];

  // If the document fits in one chunk, return it as-is
  if (text.length <= chunkSize) {
    const heading = extractCurrentHeading(text, 0);
    return [
      {
        sourceId: doc.sourceId,
        documentId: doc.id,
        title: doc.title,
        path: doc.path,
        content: text,
        chunkIndex: 0,
        chunkTotal: 1,
        contentHash: hashContent(text),
        metadata: { ...doc.metadata, headingContext: heading },
      },
    ];
  }

  // Try heading-aware splitting first
  const headingChunks = chunkByHeadings(doc, text, chunkSize, overlap);
  if (headingChunks.length > 1) {
    return headingChunks;
  }

  // Fall back to paragraph-based splitting
  const paragraphChunks = chunkByParagraphs(doc, text, chunkSize, overlap);
  if (paragraphChunks.length > 1) {
    return paragraphChunks;
  }

  // Last resort: character-based splitting
  return chunkByCharacters(doc, text, chunkSize, overlap);
}

/**
 * Split on markdown heading boundaries, preserving heading context in metadata.
 */
function chunkByHeadings(
  doc: RawDocument,
  text: string,
  chunkSize: number,
  overlap: number,
): DocumentChunk[] {
  // Split at heading lines (# ## ###)
  const headingPattern = /^(#{1,6}\s+.+)$/m;
  const lines = text.split('\n');

  const sections: { heading: string; content: string }[] = [];
  let currentHeading = '';
  let currentLines: string[] = [];

  for (const line of lines) {
    if (headingPattern.test(line)) {
      if (currentLines.join('\n').trim()) {
        sections.push({ heading: currentHeading, content: currentLines.join('\n').trim() });
      }
      currentHeading = line.trim();
      currentLines = [line];
    } else {
      currentLines.push(line);
    }
  }
  if (currentLines.join('\n').trim()) {
    sections.push({ heading: currentHeading, content: currentLines.join('\n').trim() });
  }

  if (sections.length <= 1) {
    return []; // Signal to try next strategy
  }

  // Combine sections into size-appropriate chunks
  const chunks: { content: string; heading: string }[] = [];
  let current = '';
  let currentHeadingCtx = '';

  for (const section of sections) {
    const candidate = current ? current + '\n\n' + section.content : section.content;
    if (candidate.length > chunkSize && current.length > 0) {
      chunks.push({ content: current.trim(), heading: currentHeadingCtx });
      // Overlap from end of previous chunk
      const overlapText = current.slice(-overlap);
      current = overlapText + '\n\n' + section.content;
      currentHeadingCtx = section.heading || currentHeadingCtx;
    } else {
      current = candidate;
      if (section.heading) currentHeadingCtx = section.heading;
    }
  }
  if (current.trim()) {
    chunks.push({ content: current.trim(), heading: currentHeadingCtx });
  }

  return chunks.map((c, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content: c.content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(c.content),
    metadata: { ...doc.metadata, headingContext: c.heading },
  }));
}

function chunkByParagraphs(
  doc: RawDocument,
  text: string,
  chunkSize: number,
  overlap: number,
): DocumentChunk[] {
  const paragraphs = text.split(/\n\s*\n/).filter((p) => p.trim().length > 0);
  const chunks: string[] = [];
  let current = '';

  for (const para of paragraphs) {
    if (current.length + para.length + 2 > chunkSize && current.length > 0) {
      chunks.push(current.trim());
      const overlapText = current.slice(-overlap);
      current = overlapText + '\n\n' + para;
    } else {
      current = current ? current + '\n\n' + para : para;
    }
  }
  if (current.trim()) {
    chunks.push(current.trim());
  }

  if (chunks.length <= 1) {
    return []; // Signal to try next strategy
  }

  return chunks.map((content, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(content),
    metadata: {
      ...doc.metadata,
      headingContext: extractCurrentHeading(text, text.indexOf(content)),
    },
  }));
}

function chunkByCharacters(
  doc: RawDocument,
  text: string,
  chunkSize: number,
  overlap: number,
): DocumentChunk[] {
  const chunks: string[] = [];
  let start = 0;

  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    chunks.push(text.slice(start, end));
    start = end - overlap;
    if (start >= text.length) break;
  }

  return chunks.map((content, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(content),
    metadata: {
      ...doc.metadata,
      headingContext: extractCurrentHeading(text, text.indexOf(content)),
    },
  }));
}

/**
 * Find the most recent heading at or before the given position in text.
 */
function extractCurrentHeading(text: string, position: number): string {
  const segment = text.slice(0, position + 1);
  const headingMatches = [...segment.matchAll(/^(#{1,6}\s+.+)$/gm)];
  if (headingMatches.length === 0) return '';
  return headingMatches[headingMatches.length - 1]![0]!.trim();
}

function hashContent(content: string): string {
  return createHash('sha256').update(content).digest('hex').slice(0, 16);
}

