    const candidate = current ? current + '\n\n' + section.content : section.content;
    if (candidate.length > chunkSize && current.length > 0) {
      chunks.push({ content: current.trim(), heading: currentHeadingCtx });
      const overlapText = current.slice(-overlap);
      current = overlapText + '\n\n' + section.content;
      if (section.heading) currentHeadingCtx = section.heading;
    } else {
      current = candidate;
      if (section.heading) currentHeadingCtx = section.heading;
    }
  }
  if (current.trim()) {
    chunks.push({ content: current.trim(), heading: currentHeadingCtx });
  }

  if (chunks.length <= 1) return [];

  return chunks.map((c, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content: c.content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(c.content),
    metadata: { ...doc.metadata, headingContext: c.heading },
  }));
}

function chunkByParagraphs(
  doc: RawDocument,
  text: string,
  chunkSize: number,
  overlap: number,
): DocumentChunk[] {
  const paragraphs = text.split(/\n\s*\n/).filter((p) => p.trim().length > 0);
  const chunks: string[] = [];
  let current = '';

  for (const para of paragraphs) {
    if (current.length + para.length + 2 > chunkSize && current.length > 0) {
      chunks.push(current.trim());
      const overlapText = current.slice(-overlap);
      current = overlapText + '\n\n' + para;
    } else {
      current = current ? current + '\n\n' + para : para;
    }
  }
  if (current.trim()) {
    chunks.push(current.trim());
  }

  if (chunks.length <= 1) return [];

  return chunks.map((content, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(content),
    metadata: {
      ...doc.metadata,
      headingContext: extractCurrentHeading(text, text.indexOf(content)),
    },
  }));
}

function chunkByCharacters(
  doc: RawDocument,
  text: string,
  chunkSize: number,
  overlap: number,
): DocumentChunk[] {
  const chunks: string[] = [];
  let start = 0;

  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    chunks.push(text.slice(start, end));
    start = end - overlap;
    if (start >= text.length) break;
  }

  return chunks.map((content, index) => ({
    sourceId: doc.sourceId,
    documentId: doc.id,
    title: doc.title,
    path: doc.path,
    content,
    chunkIndex: index,
    chunkTotal: chunks.length,
    contentHash: hashContent(content),
    metadata: {
      ...doc.metadata,
      headingContext: extractCurrentHeading(text, text.indexOf(content)),
    },
  }));
}

/**
 * Find the most recent heading at or before the given position in text.
 */
function extractCurrentHeading(text: string, position: number): string {
  const segment = text.slice(0, Math.max(position + 1, 1));
  const headingMatches = [...segment.matchAll(/^(#{1,6}\s+.+)$/gm)];
  if (headingMatches.length === 0) return '';
  return headingMatches[headingMatches.length - 1]![0]!.trim();
}

function hashContent(content: string): string {
  return createHash('sha256').update(content).digest('hex').slice(0, 16);
}

