import { describe, it, expect, beforeEach, vi } from 'vitest';
import { mockPrismaClient, resetPrismaMocks } from '../../__tests__/mocks/prisma';
import { MAX_CONTEXT_MESSAGES } from '@/lib/config';

// Mock the db module
vi.mock('@/lib/db', () => ({
  db: mockPrismaClient,
}));

// Mock db session/message helpers to use mock client
vi.mock('@/lib/db/sessions', async () => {
  const actual = await vi.importActual('@/lib/db/sessions');
  return actual;
});

vi.mock('@/lib/db/messages', async () => {
  const actual = await vi.importActual('@/lib/db/messages');
  return actual;
});

import { InMemorySessionStore, SessionService } from '../session-store';

// ── InMemorySessionStore tests ───────────────────────────────────────────────

describe('InMemorySessionStore', () => {
  let store: InMemorySessionStore;

  beforeEach(() => {
    store = new InMemorySessionStore();
  });

  it('starts with empty history', async () => {
    const history = await store.getHistory('session-1');
    expect(history).toEqual([]);
  });

  it('addEntry and getHistory round-trip', async () => {
    const entry = {
      role: 'user' as const,
      content: 'Hello',
      timestamp: new Date(),
    };
    await store.addEntry('session-1', entry);
    const history = await store.getHistory('session-1');
    expect(history).toHaveLength(1);
    expect(history[0]!.content).toBe('Hello');
  });

  it('getHistory respects limit', async () => {
    for (let i = 0; i < 5; i++) {
      await store.addEntry('session-1', {
        role: 'user',
        content: `Message ${i}`,
        timestamp: new Date(),
      });
    }
    const history = await store.getHistory('session-1', 3);
    expect(history).toHaveLength(3);
    expect(history[2]!.content).toBe('Message 4');
  });

  it('getContextMessages returns ChatMessage format', async () => {
    await store.addEntry('session-1', {
      role: 'user',
      content: 'Hi there',
      timestamp: new Date(),
    });
    const messages = await store.getContextMessages('session-1');
    expect(messages).toHaveLength(1);
    expect(messages[0]).toEqual({ role: 'user', content: 'Hi there' });
  });

  it('getContextMessages uses MAX_CONTEXT_MESSAGES as default', async () => {
    for (let i = 0; i < MAX_CONTEXT_MESSAGES + 5; i++) {
      await store.addEntry('session-1', {
        role: 'user',
        content: `Msg ${i}`,
        timestamp: new Date(),
      });
    }
    const messages = await store.getContextMessages('session-1');
    expect(messages).toHaveLength(MAX_CONTEXT_MESSAGES);
  });

  it('clear removes all entries for a session', async () => {
    await store.addEntry('session-1', { role: 'user', content: 'Hi', timestamp: new Date() });
    await store.clear('session-1');
    const history = await store.getHistory('session-1');
    expect(history).toEqual([]);
  });

  it('sessions are isolated from each other', async () => {
    await store.addEntry('session-1', { role: 'user', content: 'A', timestamp: new Date() });
    await store.addEntry('session-2', { role: 'user', content: 'B', timestamp: new Date() });
    const h1 = await store.getHistory('session-1');
    const h2 = await store.getHistory('session-2');
    expect(h1).toHaveLength(1);
    expect(h2).toHaveLength(1);
    expect(h1[0]!.content).toBe('A');
    expect(h2[0]!.content).toBe('B');
  });
});

// ── SessionService tests ─────────────────────────────────────────────────────

describe('SessionService', () => {
  let service: SessionService;

  beforeEach(() => {
    resetPrismaMocks();
    service = new SessionService();
  });

  describe('createSession', () => {
    it('creates session with defaults via db helper', async () => {
      const mockSession = {
        id: 'session-uuid',
        channel: 'web',
        language: 'en',
        isActive: true,
        userId: null,
        title: null,
        metadata: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      mockPrismaClient.session.create.mockResolvedValueOnce(mockSession);

      const session = await service.createSession({ channel: 'web' });
      expect(session.id).toBe('session-uuid');
      expect(mockPrismaClient.session.create).toHaveBeenCalledOnce();
    });

    it('creates session with custom language', async () => {
      const mockSession = {
        id: 'sess-fr',
        channel: 'web',
        language: 'fr',
        isActive: true,
        userId: null,
        title: null,
        metadata: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      mockPrismaClient.session.create.mockResolvedValueOnce(mockSession);

      const session = await service.createSession({ channel: 'web', language: 'fr' });
      expect(session.language).toBe('fr');
    });
  });

  describe('getSession', () => {
    it('returns session when found', async () => {
      const mockSession = { id: 'sess-1', channel: 'web', language: 'en' };
      mockPrismaClient.session.findUnique.mockResolvedValueOnce(mockSession);

      const session = await service.getSession('sess-1');
      expect(session).toBeDefined();
      expect(session!.id).toBe('sess-1');
    });

    it('returns null when not found', async () => {
      mockPrismaClient.session.findUnique.mockResolvedValueOnce(null);

      const session = await service.getSession('nonexistent');
      expect(session).toBeNull();
    });
  });

  describe('updateSession', () => {
    it('updates session fields', async () => {
      const mockSession = { id: 'sess-1', language: 'fr', isActive: false };
      mockPrismaClient.session.update.mockResolvedValueOnce(mockSession);

      const session = await service.updateSession('sess-1', { language: 'fr', isActive: false });
      expect(session.language).toBe('fr');
      expect(mockPrismaClient.session.update).toHaveBeenCalledOnce();
    });
  });

  describe('addMessage', () => {
    it('persists a message via db helper', async () => {
      const mockMsg = {
        id: 'msg-1',
        sessionId: 'sess-1',
        role: 'user',
        content: 'Hello',
        createdAt: new Date(),
      };
      mockPrismaClient.message.create.mockResolvedValueOnce(mockMsg);

      const msg = await service.addMessage({
        sessionId: 'sess-1',
        role: 'user',
        content: 'Hello',
      });
      expect(msg.id).toBe('msg-1');
      expect(msg.content).toBe('Hello');
    });
  });

  describe('getMessages', () => {
    it('returns messages ordered ascending by default', async () => {
      const msgs = [
        { id: 'm1', role: 'user', content: 'A', createdAt: new Date(1) },
        { id: 'm2', role: 'assistant', content: 'B', createdAt: new Date(2) },
      ];
      mockPrismaClient.message.findMany.mockResolvedValueOnce(msgs);

      const result = await service.getMessages('sess-1');
      expect(result).toHaveLength(2);
      expect(result[0]!.content).toBe('A');
    });

    it('respects limit option', async () => {
      mockPrismaClient.message.findMany.mockResolvedValueOnce([]);
      await service.getMessages('sess-1', { limit: 5 });
      expect(mockPrismaClient.message.findMany).toHaveBeenCalledWith(
        expect.objectContaining({ take: 5 }),
      );
    });
  });

  describe('loadContext', () => {
    it('returns messages in chronological order', async () => {
      // Returns desc order from DB, should be reversed
      const msgs = [
        { id: 'm2', role: 'assistant', content: 'World', toolName: null, toolCallId: null, createdAt: new Date(2) },
        { id: 'm1', role: 'user', content: 'Hello', toolName: null, toolCallId: null, createdAt: new Date(1) },
      ];
      mockPrismaClient.message.findMany.mockResolvedValueOnce(msgs);

      const context = await service.loadContext('sess-1');
      expect(context).toHaveLength(2);
      expect(context[0]!.content).toBe('World'); // reversed from desc
      expect(context[1]!.content).toBe('Hello');
    });

    it('maps to ChatMessage format', async () => {
      const msgs = [
        { id: 'm1', role: 'user', content: 'Hello', toolName: null, toolCallId: null, createdAt: new Date() },
      ];
      mockPrismaClient.message.findMany.mockResolvedValueOnce(msgs);

      const context = await service.loadContext('sess-1');
      expect(context[0]).toMatchObject({ role: 'user', content: 'Hello' });
    });

    it('includes toolCallId for tool messages', async () => {
      const msgs = [
        {
          id: 'm1',
          role: 'tool',
          content: 'result',
          toolName: 'searchKnowledgeBase',
          toolCallId: 'call-123',
          createdAt: new Date(),
        },
      ];
      mockPrismaClient.message.findMany.mockResolvedValueOnce(msgs);

      const context = await service.loadContext('sess-1');
      expect(context[0]!.toolCallId).toBe('call-123');
      expect(context[0]!.name).toBe('searchKnowledgeBase');
    });

    it('uses MAX_CONTEXT_MESSAGES as default limit', async () => {
      mockPrismaClient.message.findMany.mockResolvedValueOnce([]);
      await service.loadContext('sess-1');
      expect(mockPrismaClient.message.findMany).toHaveBeenCalledWith(
        expect.objectContaining({ take: MAX_CONTEXT_MESSAGES }),
      );
    });

    it('returns empty array for session with no messages', async () => {
      mockPrismaClient.message.findMany.mockResolvedValueOnce([]);
      const context = await service.loadContext('sess-1');
      expect(context).toEqual([]);
    });
  });
});

