      expect(memories).toHaveLength(1);
      expect(memories[0]!.key).toBe('name');
      expect(memories[0]!.value).toBe('Alice');
    });

    it('upserts on same key', async () => {
      await store.saveMemory('user-1', {
        key: 'name',
        value: 'Alice',
        source: 'conversation',
        confidence: 0.9,
        updatedAt: new Date(),
      });
      await store.saveMemory('user-1', {
        key: 'name',
        value: 'Bob',
        source: 'profile',
        confidence: 1.0,
        updatedAt: new Date(),
      });
      const memories = await store.getMemories('user-1');
      expect(memories).toHaveLength(1);
      expect(memories[0]!.value).toBe('Bob');
    });
  });

  describe('getMemory', () => {
    it('returns null for missing key', async () => {
      const mem = await store.getMemory('user-1', 'nonexistent');
      expect(mem).toBeNull();
    });

    it('returns specific memory by key', async () => {
      await store.saveMemory('user-1', {
        key: 'lang',
        value: 'fr',
        source: 'conversation',
        confidence: 1,
        updatedAt: new Date(),
      });
      const mem = await store.getMemory('user-1', 'lang');
      expect(mem).not.toBeNull();
      expect(mem!.value).toBe('fr');
    });
  });

  describe('deleteMemory', () => {
    it('removes a memory', async () => {
      await store.saveMemory('user-1', {
        key: 'x',
        value: 'y',
        source: 'conversation',
        confidence: 1,
        updatedAt: new Date(),
      });
      await store.deleteMemory('user-1', 'x');
      const mem = await store.getMemory('user-1', 'x');
      expect(mem).toBeNull();
    });
  });

  describe('getMemorySummary', () => {
    it('returns empty string for user with no memories', async () => {
      const summary = await store.getMemorySummary('user-1');
      expect(summary).toBe('');
    });

    it('formats memories as bullet list', async () => {
      await store.saveMemory('user-1', {
        key: 'name',
        value: 'Alice',
        source: 'conversation',
        confidence: 1,
        updatedAt: new Date(),
      });
      const summary = await store.getMemorySummary('user-1');
      expect(summary).toContain('name: Alice');
    });
  });

  describe('session-scoped memory', () => {
    it('setSessionMemory and getSessionMemory round-trip', async () => {
      await store.setSessionMemory('sess-1', 'topic', 'coding');
      const memory = await store.getSessionMemory('sess-1');
      expect(memory).toEqual({ topic: 'coding' });
    });

    it('upserts session memory on same key', async () => {
      await store.setSessionMemory('sess-1', 'topic', 'coding');
      await store.setSessionMemory('sess-1', 'topic', 'news');
      const memory = await store.getSessionMemory('sess-1');
      expect(memory['topic']).toBe('news');
    });

    it('sessions are isolated', async () => {
      await store.setSessionMemory('sess-1', 'topic', 'coding');
      await store.setSessionMemory('sess-2', 'topic', 'news');
      const m1 = await store.getSessionMemory('sess-1');
      const m2 = await store.getSessionMemory('sess-2');
      expect(m1['topic']).toBe('coding');
      expect(m2['topic']).toBe('news');
    });

    it('returns empty object for session with no memory', async () => {
      const memory = await store.getSessionMemory('sess-unknown');
      expect(memory).toEqual({});
    });
  });
});

