import { describe, it, expect, beforeEach } from 'vitest';
import { z } from 'zod';
import { ToolRegistry } from '../registry-test-helper';
import type { SandraTool, ToolResult } from '../types';

// We can't import from registry directly since it's a singleton.
// Create a fresh ToolRegistry class for isolation.
// We'll use a local helper that re-creates the class.

function makeTestTool(name: string, scopes: string[] = []): SandraTool {
  return {
    name,
    description: `Test tool ${name}`,
    parameters: { type: 'object', properties: { input: { type: 'string' } }, required: [] },
    inputSchema: z.object({ input: z.string().optional() }),
    requiredScopes: scopes,
    async execute(): Promise<ToolResult> {
      return { success: true, data: { name } };
    },
  };
}

// Test using a fresh registry instance by importing the class directly
import { getToolRegistry, toolRegistry } from '../registry';

describe('ToolRegistry', () => {
  beforeEach(() => {
    // Clear the global singleton for test isolation
    toolRegistry.clear();
  });

  it('registers a tool and retrieves it by name', () => {
    const tool = makeTestTool('myTool');
    toolRegistry.register(tool);
    expect(toolRegistry.get('myTool')).toBe(tool);
  });

  it('has() returns true for registered tools', () => {
    const tool = makeTestTool('myTool');
    toolRegistry.register(tool);
    expect(toolRegistry.has('myTool')).toBe(true);
    expect(toolRegistry.has('other')).toBe(false);
  });

  it('throws on duplicate registration', () => {
    toolRegistry.register(makeTestTool('dupe'));
    expect(() => toolRegistry.register(makeTestTool('dupe'))).toThrow(/already registered/i);
  });

  it('getAll() returns all registered tools', () => {
    toolRegistry.register(makeTestTool('tool1'));
    toolRegistry.register(makeTestTool('tool2'));
    const all = toolRegistry.getAll();
    expect(all).toHaveLength(2);
    const names = all.map((t) => t.name);
    expect(names).toContain('tool1');
    expect(names).toContain('tool2');
  });

  it('getToolDefinitions() returns OpenAI function-call format', () => {
    toolRegistry.register(makeTestTool('myTool'));
    const defs = toolRegistry.getToolDefinitions();
    expect(defs).toHaveLength(1);
    expect(defs[0]).toMatchObject({
      name: 'myTool',
      description: 'Test tool myTool',
      parameters: expect.objectContaining({ type: 'object' }),
    });
  });

  it('getToolNames() returns all registered names', () => {
    toolRegistry.register(makeTestTool('a'));
    toolRegistry.register(makeTestTool('b'));
    expect(toolRegistry.getToolNames()).toEqual(['a', 'b']);
  });

  it('clear() removes all tools', () => {
    toolRegistry.register(makeTestTool('tool'));
    toolRegistry.clear();
    expect(toolRegistry.getAll()).toHaveLength(0);
  });

  it('getToolRegistry() returns the same singleton', () => {
    expect(getToolRegistry()).toBe(toolRegistry);
  });
});

