import { describe, it, expect, beforeEach } from 'vitest';
import { z } from 'zod';
import { toolRegistry } from '../registry';
import { executeTool } from '../executor';
import type { SandraTool, ToolResult, ToolContext } from '../types';

function makeTestTool(
  name: string,
  opts: {
    scopes?: string[];
    handler?: () => Promise<ToolResult>;
    schema?: z.ZodSchema;
  } = {},
): SandraTool {
  return {
    name,
    description: `Test ${name}`,
    parameters: { type: 'object', properties: {}, required: [] },
    inputSchema: opts.schema ?? z.object({}),
    requiredScopes: opts.scopes ?? [],
    execute:
      opts.handler ??
      (async () => ({ success: true, data: 'ok' })),
  };
}

const fullScopeCtx: ToolContext = {
  sessionId: 'sess-1',
  scopes: ['knowledge:read', 'repos:read'],
};

describe('executeTool', () => {
  beforeEach(() => {
    toolRegistry.clear();
  });

  it('returns error result for unknown tool', async () => {
    const result = await executeTool('unknown', '{}', fullScopeCtx);
    expect(result.success).toBe(false);
    expect(result.error).toMatch(/not found/i);
  });

  it('returns error result for invalid JSON', async () => {
    toolRegistry.register(makeTestTool('myTool'));
    const result = await executeTool('myTool', 'not-json', fullScopeCtx);
    expect(result.success).toBe(false);
    expect(result.error).toMatch(/invalid json/i);
  });

  it('throws AuthError when required scopes are missing', async () => {
    toolRegistry.register(makeTestTool('secured', { scopes: ['admin:write'] }));
    await expect(
      executeTool('secured', '{}', { sessionId: 'sess-1', scopes: [] }),
    ).rejects.toThrow(/missing required scopes/i);
  });

  it('throws ValidationError for invalid input', async () => {
    const tool = makeTestTool('strict', {
      schema: z.object({ name: z.string() }),
    });
    toolRegistry.register(tool);
    await expect(
      executeTool('strict', '{"name": 123}', fullScopeCtx),
    ).rejects.toThrow(/validation failed/i);
  });

  it('executes successfully and returns ToolResult', async () => {
    toolRegistry.register(
      makeTestTool('happy', {
        handler: async () => ({ success: true, data: { answer: 42 } }),
      }),
    );
    const result = await executeTool('happy', '{}', fullScopeCtx);
    expect(result.success).toBe(true);
    expect(result.data).toEqual({ answer: 42 });
  });

  it('returns ToolResult with success:false when handler throws (not re-thrown)', async () => {
    toolRegistry.register(
      makeTestTool('throws', {
        handler: async () => {
          throw new Error('handler boom');
        },
      }),
    );
    const result = await executeTool('throws', '{}', fullScopeCtx);
    expect(result.success).toBe(false);
    expect(result.error).toBe('handler boom');
  });

  it('uses default empty scopes when context is omitted', async () => {
    // Tool with no required scopes — should work without context
    toolRegistry.register(makeTestTool('noScopes'));
    const result = await executeTool('noScopes', '{}');
    expect(result.success).toBe(true);
  });

  it('passes only required scopes check (not superset)', async () => {
    toolRegistry.register(makeTestTool('partial', { scopes: ['repos:read'] }));
    const result = await executeTool(
      'partial',
      '{}',
      { sessionId: 'x', scopes: ['repos:read', 'extra:scope'] },
    );
    expect(result.success).toBe(true);
  });
});

