import { describe, it, expect } from 'vitest';
import { chunkDocument } from '../chunker';
import type { RawDocument } from '../types';

function makeDoc(content: string, opts: Partial<RawDocument> = {}): RawDocument {
  return {
    sourceId: 'src-1',
    title: 'Test Doc',
    content,
    ...opts,
  };
}

describe('chunkDocument', () => {
  it('returns empty array for empty content', () => {
    const chunks = chunkDocument(makeDoc(''));
    expect(chunks).toHaveLength(0);
  });

  it('returns single chunk for short document', () => {
    const content = 'Short document content';
    const chunks = chunkDocument(makeDoc(content), { chunkSize: 1000 });
    expect(chunks).toHaveLength(1);
    expect(chunks[0]!.content).toBe(content);
    expect(chunks[0]!.chunkIndex).toBe(0);
    expect(chunks[0]!.chunkTotal).toBe(1);
  });

  it('produces multiple chunks for long document', () => {
    const content = 'A'.repeat(3000);
    const chunks = chunkDocument(makeDoc(content), { chunkSize: 1000, chunkOverlap: 100 });
    expect(chunks.length).toBeGreaterThan(1);
  });

