import { describe, it, expect, beforeEach } from 'vitest';
import { InMemoryVectorStore, getVectorStore, setVectorStore } from '../vector-store';
import type { EmbeddedChunk } from '../types';

function makeChunk(id: string, embedding: number[], content = 'test content'): EmbeddedChunk {
  return {
    sourceId: 'src-1',
    content,
    chunkIndex: 0,
    chunkTotal: 1,
    contentHash: id,
    embedding,
  };
}

describe('InMemoryVectorStore', () => {
  let store: InMemoryVectorStore;

  beforeEach(() => {
    store = new InMemoryVectorStore();
  });

  describe('upsert and count', () => {
    it('starts empty', async () => {
      expect(await store.count()).toBe(0);
    });

    it('adds chunks and updates count', async () => {
      await store.upsert([
        makeChunk('a', [1, 0, 0]),
        makeChunk('b', [0, 1, 0]),
      ]);
      expect(await store.count()).toBe(2);
    });

    it('deduplicates chunks by sourceId+contentHash', async () => {
      const chunk = makeChunk('hash1', [1, 0, 0]);
      await store.upsert([chunk]);
      await store.upsert([{ ...chunk, content: 'updated' }]);
      expect(await store.count()).toBe(1);
    });

    it('count by sourceId returns filtered count', async () => {
      await store.upsert([
        { ...makeChunk('a', [1, 0, 0]), sourceId: 'src-1' },
        { ...makeChunk('b', [0, 1, 0]), sourceId: 'src-2' },
      ]);
      expect(await store.count('src-1')).toBe(1);
      expect(await store.count('src-2')).toBe(1);
    });
  });

  describe('search (cosine similarity)', () => {
    beforeEach(async () => {
      await store.upsert([
        makeChunk('x', [1, 0, 0], 'content about X'),
        makeChunk('y', [0, 1, 0], 'content about Y'),
        makeChunk('z', [0, 0, 1], 'content about Z'),
      ]);
    });

    it('returns empty array for empty store', async () => {
      const empty = new InMemoryVectorStore();
      const results = await empty.search([1, 0, 0], 3);
      expect(results).toHaveLength(0);
    });

    it('returns top-K results sorted by score descending', async () => {
      const results = await store.search([1, 0, 0], 3);
      expect(results).toHaveLength(3);
      // [1,0,0] is most similar to [1,0,0]
      expect(results[0]!.score).toBeGreaterThan(results[1]!.score);
    });

    it('[1,0,0] is most similar to [1,0,0] chunk', async () => {
      const results = await store.search([1, 0, 0], 3);
      expect(results[0]!.chunk.content).toBe('content about X');
      expect(results[0]!.score).toBeCloseTo(1.0);
    });

    it('[0,1,0] is most similar to [0,1,0] chunk', async () => {
      const results = await store.search([0, 1, 0], 3);
      expect(results[0]!.chunk.content).toBe('content about Y');
    });

    it('[1,0,0] has score ~0 against [0,1,0] and [0,0,1]', async () => {
      const results = await store.search([1, 0, 0], 3);
      expect(results[1]!.score).toBeCloseTo(0, 5);
      expect(results[2]!.score).toBeCloseTo(0, 5);
    });

    it('respects topK limit', async () => {
      const results = await store.search([1, 0, 0], 1);
      expect(results).toHaveLength(1);
    });

    it('search result chunks do not include embedding', async () => {
      const results = await store.search([1, 0, 0], 1);
      expect((results[0]!.chunk as unknown as { embedding?: unknown }).embedding).toBeUndefined();
    });
  });

  describe('deleteBySource', () => {
    it('removes all chunks for a source', async () => {
      await store.upsert([
        { ...makeChunk('a', [1, 0, 0]), sourceId: 'src-A' },
        { ...makeChunk('b', [0, 1, 0]), sourceId: 'src-B' },
      ]);
      await store.deleteBySource('src-A');
      expect(await store.count('src-A')).toBe(0);
      expect(await store.count('src-B')).toBe(1);
    });
  });

  describe('isReady', () => {
    it('returns true', async () => {
      expect(await store.isReady()).toBe(true);
    });
  });
});

describe('getVectorStore / setVectorStore', () => {
  it('returns a singleton', () => {
    const a = getVectorStore();
    const b = getVectorStore();
    expect(a).toBe(b);
  });

  it('setVectorStore replaces the singleton', () => {
    const custom = new InMemoryVectorStore();
    setVectorStore(custom);
    expect(getVectorStore()).toBe(custom);
    // Reset to fresh instance
    setVectorStore(new InMemoryVectorStore());
  });
});

