import { describe, it, expect, beforeEach, vi } from 'vitest';
import { mockAIProvider, resetAIProviderMocks } from '../../__tests__/mocks/ai-provider';
import { InMemoryVectorStore, setVectorStore } from '../vector-store';

vi.mock('@/lib/ai', () => ({ getAIProvider: () => mockAIProvider }));

import { retrieveContext, formatRetrievalContext } from '../retrieval';

describe('retrieveContext', () => {
  let vectorStore: InMemoryVectorStore;

  beforeEach(() => {
    resetAIProviderMocks();
    vectorStore = new InMemoryVectorStore();
    setVectorStore(vectorStore);
  });

  it('returns empty array when vector store is empty', async () => {
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[...Array(1536)].map(() => 0)],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 5 },
    });
    const results = await retrieveContext('test query');
    expect(results).toEqual([]);
  });

  it('returns results when vector store has matching content', async () => {
    // Seed the vector store
    await vectorStore.upsert([
      {
        sourceId: 'src-1',
        content: 'EdLight Code platform',
        chunkIndex: 0,
        chunkTotal: 1,
        contentHash: 'hash1',
        embedding: [1, 0, 0, ...Array(1533).fill(0)],
      },
    ]);

    // Mock query embedding matching the stored embedding
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[1, 0, 0, ...Array(1533).fill(0)]],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 5 },
    });

    const results = await retrieveContext('EdLight Code', { minScore: 0.9 });
    expect(results).toHaveLength(1);
    expect(results[0]!.chunk.content).toBe('EdLight Code platform');
    expect(results[0]!.score).toBeCloseTo(1.0);
  });

  it('filters results by minScore', async () => {
    await vectorStore.upsert([
      {
        sourceId: 'src-1',
        content: 'High relevance content',
        chunkIndex: 0,
        chunkTotal: 1,
        contentHash: 'hash1',
        embedding: [1, 0, 0],
      },
      {
        sourceId: 'src-2',
        content: 'Low relevance content',
        chunkIndex: 0,
        chunkTotal: 1,
        contentHash: 'hash2',
        embedding: [0, 1, 0],
      },
    ]);

    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[1, 0, 0]],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 5 },
    });

    const results = await retrieveContext('test', { minScore: 0.9 });
    expect(results).toHaveLength(1);
    expect(results[0]!.chunk.content).toBe('High relevance content');
  });

  it('returns empty array on embedding failure (graceful)', async () => {
    mockAIProvider.generateEmbeddings.mockRejectedValue(new Error('API unavailable'));
    const results = await retrieveContext('test query');
    expect(results).toEqual([]);
  });
});

describe('formatRetrievalContext', () => {
  it('returns empty string for empty results', () => {
    expect(formatRetrievalContext([])).toBe('');
  });

  it('formats results with title and content', () => {
    const results = [
      {
        chunk: {
          sourceId: 'src-1',
          content: 'EdLight is great',
          title: 'About EdLight',
          path: '/docs/about.md',
          chunkIndex: 0,
          chunkTotal: 1,
          contentHash: 'abc',
        },
        score: 0.9,
      },
    ];
    const formatted = formatRetrievalContext(results);
    expect(formatted).toContain('About EdLight');
    expect(formatted).toContain('EdLight is great');
    expect(formatted).toContain('/docs/about.md');
  });

  it('includes separator between multiple results', () => {
    const results = [
      {
        chunk: { sourceId: 's1', content: 'First', chunkIndex: 0, chunkTotal: 2, contentHash: 'h1' },
        score: 0.9,
      },
      {
        chunk: { sourceId: 's1', content: 'Second', chunkIndex: 1, chunkTotal: 2, contentHash: 'h2' },
        score: 0.8,
      },
    ];
    const formatted = formatRetrievalContext(results);
    expect(formatted).toContain('---');
  });
});

