import { describe, it, expect, beforeEach, vi } from 'vitest';
import { mockAIProvider, resetAIProviderMocks } from '../../__tests__/mocks/ai-provider';
import { InMemoryVectorStore, setVectorStore } from '../vector-store';

vi.mock('@/lib/ai', () => ({ getAIProvider: () => mockAIProvider }));

import { ingestDocuments, removeSource } from '../ingest';

describe('ingestDocuments', () => {
  let vectorStore: InMemoryVectorStore;

  beforeEach(() => {
    resetAIProviderMocks();
    vectorStore = new InMemoryVectorStore();
    setVectorStore(vectorStore);
    // Mock embeddings to return deterministic vectors
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[1, 0, 0, ...Array(1533).fill(0)]],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 10 },
    });
  });

  it('returns zero counts for empty documents array', async () => {
    const result = await ingestDocuments([]);
    expect(result.totalDocuments).toBe(0);
    expect(result.totalChunks).toBe(0);
  });

  it('returns zero chunks for documents with empty content', async () => {
    const result = await ingestDocuments([
      { sourceId: 'src-1', title: 'Empty', content: '' },
    ]);
    expect(result.totalChunks).toBe(0);
  });

  it('ingests a document and increases vector store count', async () => {
    // Need to mock embeddings for each chunk that will be created
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [
        [1, 0, 0, ...Array(1533).fill(0)],
        [0, 1, 0, ...Array(1533).fill(0)],
      ],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 10 },
    });

    const result = await ingestDocuments([
      {
        sourceId: 'src-1',
        title: 'EdLight README',
        content: 'EdLight is a platform for education.\n\nIt provides tools for teachers.',
      },
    ]);

    expect(result.totalDocuments).toBe(1);
    expect(result.totalChunks).toBeGreaterThan(0);
    expect(await vectorStore.count()).toBe(result.totalChunks);
  });

  it('processes multiple documents sequentially', async () => {
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[1, 0, 0, ...Array(1533).fill(0)]],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 5 },
    });

    const result = await ingestDocuments([
      { sourceId: 'src-1', title: 'Doc 1', content: 'First document content.' },
      { sourceId: 'src-2', title: 'Doc 2', content: 'Second document content.' },
    ]);

    expect(result.totalDocuments).toBe(2);
    expect(result.totalChunks).toBeGreaterThan(0);
  });

  it('stores chunks with source metadata', async () => {
    mockAIProvider.generateEmbeddings.mockResolvedValue({
      embeddings: [[1, 0, 0, ...Array(1533).fill(0)]],
      model: 'text-embedding-3-small',
      usage: { totalTokens: 5 },
    });

    await ingestDocuments([
      { sourceId: 'my-source', title: 'Doc', content: 'Some content here.' },
    ]);

    expect(await vectorStore.count('my-source')).toBeGreaterThan(0);
  });
});

describe('removeSource', () => {
  let vectorStore: InMemoryVectorStore;

  beforeEach(() => {
    resetAIProviderMocks();
    vectorStore = new InMemoryVectorStore();
    setVectorStore(vectorStore);
  });

  it('removes all chunks for a source', async () => {
    // Seed the store directly
    await vectorStore.upsert([
      {
        sourceId: 'src-to-remove',
        content: 'content',
        chunkIndex: 0,
        chunkTotal: 1,
        contentHash: 'h1',
        embedding: [1, 0, 0],
      },
    ]);
    expect(await vectorStore.count('src-to-remove')).toBe(1);

    await removeSource('src-to-remove');
    expect(await vectorStore.count('src-to-remove')).toBe(0);
  });
});

